INSERT INTO public.organizations (organization_id, name, description, website, contact_email) VALUES
(1, 'Фонд Повернись Живим', 'Фонд «Повернись живим» — одна з найвідоміших українських благодійних організацій компетентної допомоги армії, що з 2014 року системно підсилює Сили оборони України. Місія фонду — забезпечити технологічну перевагу українських військових і підвищити стійкість сектору безпеки та оборони. Організація спрямовує донати та пожертви на закупівлю і передачу підрозділам транспортних засобів, оптики, енергетичного, зв’язкового та розвідувального обладнання, зокрема безпілотних систем. Важливим напрямом роботи є навчальні проєкти: підготовка саперів, снайперів, фахівців зі стрільби із закритих позицій, операторів БпЛА, а також тренінги з тактичної медицини. Фонд розвиває аналітику у сфері оборони, готує дослідження для ухвалення зважених рішень та підтримує ветеранські ініціативи через спорт і реабілітаційні програми. «Повернись живим» діє прозоро: публікує звітність про надходження, закупівлі та передачі, дотримується внутрішніх політик комплаєнсу й міжнародних стандартів управління якістю. Фонд працює виключно з офіційними запитами військових частин і передає майно на баланс, що гарантує цільове використання допомоги. Підтримати діяльність можна разовими чи регулярними внесками, корпоративними пожертвами, партнерськими проєктами або благодійними зборами. «Повернись живим» об’єднує донорів, волонтерів, бізнес і громади заради посилення обороноздатності, захисту військових і сталого відновлення України, забезпечуючи ефективну, підзвітну та результативну допомогу.', 'https://savelife.in.ua/', 'office@savelife.in.ua'),
(2, 'Благодійний Фонд Сергія Притули', 'Благодійний Фонд Сергія Притули — українська неприбуткова організація, що системно допомагає Збройним Силам України та цивільним, які постраждали від війни. Фонд об’єднує донати громадян, бізнесу та міжнародних партнерів, перетворюючи пожертви на реальну підтримку оборони й гуманітарної сфери. Військовий напрям зосереджений на посиленні підрозділів: закупівля та передача безпілотників (БпЛА), засобів зв’язку, оптики, засобів радіоелектронної боротьби, транспортних засобів, тактичної медицини, а також ремонт і дообладнання техніки, комплектація командно-штабних машин. Окрема увага приділяється підготовці, тренінгам і навчальним програмам для військових та інструкторів, розвитку спроможностей підрозділів і безпеці на фронті.
INSERT INTO public.projects (project_id, name, description, organization_id) OVERRIDING SYSTEM VALUE VALUES
(1, 'Дронопад (Dronefall)', '«Дронопад» — це стратегічний благодійний проєкт Фонду «Повернись живим», спрямований на системне зниження загрози з повітря для українських військових і цивільних. Ініціатива забезпечує підрозділи прикриття комплексом рішень для перехоплення ворожих розвідувальних і ударних БпЛА: від модифікованих FPV-дронів-перехоплювачів і пікапів до засобів зв’язку, живлення, ретрансляторів сигналу, антен, нічної оптики та елементів радіоелектронної боротьби. Принцип «Дронопаду» — не просто купити техніку, а зібрати для екіпажів повний, збалансований набір і навчання, завдяки якому кожна пожертва перетворюється на вимірюваний оборонний ефект. Команда Фонду спільно з військовими аналізує типи ворожих безпілотників і під це конфігурує спорядження, а також публікує матеріали про методологію й проміжні результати, демонструючи прозорість і звітність перед благодійниками. До ініціативи долучаються бізнес-партнери й волонтери, а донати небайдужих громадян України та діаспори дозволяють масштабувати мережу екіпажів-перехоплювачів на різних напрямках. «Дронопад» робить боротьбу з БпЛА економічно ефективною (замість дорогих ЗРК — точні FPV‑перехоплення), підсилює стійкість ППО та зменшує навантаження на ракетні підрозділи. Це — приклад сучасної благодійності, коли кожна гривня підтримки, кожен донат і пожертва конвертуються у конкретні збиті «крила» ворога, а волонтерська енергія поєднується з військовою експертизою для захисту неба України з максимальною прозорістю.', 1),
(2, 'Нам тут жити: Місія 077', '«Місія 077» — спільний проєкт Фонду «Повернись живим» та національного оператора зв’язку, створений для розбудови сучасної, стійкої й багаторівневої системи військових комунікацій на північному напрямку оборони. Мета ініціативи — профінансувати архітектуру зв’язку для чотирьох новостворених корпусів: закупити термінали супутникового зв’язку, джерела безперебійного живлення, телекомунікаційні контейнери, пікапи, кабелі та іншу інфраструктурну техніку. Надійний зв’язок — основа керованості підрозділів, швидкості ухвалення рішень і взаємодії між розвідкою, артилерією, піхотою та ППО. Саме тому кожна пожертва в цей збір напряму впливає на збереження життів і ефективність операцій. Проєкт публічно анонсований із чіткою метою у гривнях, що підкреслює прозорість і підзвітність Фонду: благодійники бачать прогрес, а партнери медіа підсилюють охоплення для швидшого досягнення цілі. «Місія 077» поєднує благодійність, корпоративну соціальну відповідальність і волонтерську підтримку, створюючи масштабний ефект для обороноздатності України. Донати громадян, бізнесу й діаспори допомагають розбудувати «нервову систему» війська, щоб командири на усіх рівнях мали стійкі канали зв’язку, а система управління боєм працювала без збоїв у найскладніших умовах.', 1),
(3, 'Школа РЕБ «SPECTRE»', 'Школа РЕБ «SPECTRE» — флагманський освітній проєкт «Повернись живим», створений разом із 155-м Навчальним центром Сухопутних військ для підготовки операторів і техніків радіоелектронної боротьби та радіоелектронної розвідки. На відміну від стихійного навчання «в полі», школа систематизує знання і дає військово-облікові спеціальності (зокрема ВОС 545 та 786), навчає встановлювати комплекси РЕБ на різні платформи, правильно експлуатувати, ремонтувати й інтегрувати їх у бойові порядки. Фонд забезпечує школу всім необхідним: зв’язком і тренувальним обладнанням, автотранспортом для польових занять, побутовою інфраструктурою (від пралень і душових до спортивних залів), укриттями та майстернями для відпрацювання ремонту. Інструктори «SPECTRE» — чинні військові з реальним бойовим досвідом і підготовкою за сучасними стандартами лідерства, що гарантує практичний, а не теоретичний підхід. Кожен донат і пожертва у розвиток школи — це вклад у людей, які «завойовують радіоефір» і позбавляють ворога можливості бачити, коригувати вогонь і координувати дії. Проєкт поєднує волонтерську підтримку, благодійні внески бізнесу та громадян і підходи прозорості та звітності, щоб кожна гривня приносила вимірюваний ефект на полі бою. У підсумку Школа РЕБ «SPECTRE» підсилює технологічну перевагу України, зменшуючи втрати та роблячи наші підрозділи більш захищеними і результативними.', 1),
(4, 'Проєкт 61: мобільні комплекси для обслуговування озброєння F‑16 та комплекс планування місій', '«Проєкт 61» — це інженерне рішення Фонду «Повернись живим» на запит Міністерства оборони України: мобільні комплекси для підготовки та навішування авіаційних засобів ураження на винищувачі F‑16, а також окремий комплекс планування місій. На відміну від класичної «стаціонарної» моделі, мобільні системи дозволяють виконувати регламентні й підготовчі роботи на як основних, так і на тимчасових аеродромах або місцях екстреного приземлення, зменшуючи уразливість авіації для ракетних ударів. Комплекси включають майстерню для перевірки й підготовки озброєння, спеціальні вантажні фургони для транспортування й навішування боєприпасів та пікап для логістики; комплекс планування місій складається з операційного й житлового модулів для тривалої автономної роботи групи. Проєкт демонструє, як благодійність, високі стандарти прозорості та звітності і партнерство з державними та корпоративними донорами дозволяють вирішувати «вузькі місця» оборони швидко й технологічно. Кожен донат тут безпосередньо підвищує темп бойової роботи авіації та її стійкість до загроз, а волонтерська експертиза команди Фонду допомагає адаптувати рішення під реальні потреби Повітряних Сил України.', 1),
(5, 'Другий рубіж ППО — мобільні вогневі групи', '«Другий рубіж ППО» — це напрям, у межах якого «Повернись живим» долучився до державної програми розгортання мобільних вогневих груп у всіх регіонах країни для підсилення захисту неба. Суть підходу — зробити ППО більш гнучкою та «розшитою» по місцевості: мобільні екіпажі діють із пікапів чи вантажівок, швидко змінюють позиції, прикривають критичну інфраструктуру та цивільні об’єкти від «Шахедів», крилатих ракет і розвідувальних БпЛА. Фонд комплексно забезпечує такі групи зв’язком, джерелами живлення, тепловізійною оптикою, спорядженням і супутніми засобами, підвищуючи їхню ефективність і автономність. Паралельно реалізуються споріднені кампанії з посилення засобів управління, зв’язку та мобільних пунктів — це дозволяє швидше виявляти цілі, ухвалювати рішення і координувати вогонь. Проєкт поєднує донати громадян, бізнес-партнерів і міжнародних друзів України та підкріплений публічними матеріалами Фонду, що засвідчують реальні передачі майна і результати на напрямках. Завдяки прозорості та звітності благодійники розуміють, як їхні пожертви конвертуються у збиті цілі й збережені життя. Це сучасний формат гуманітарної допомоги для сектору безпеки, в якому волонтерські ініціативи доповнюють державні програми, підвищуючи стійкість українського неба.', 1),
(6, 'HOLDING YOU! — навчально‑тренувальні комплекси з тактичної медицини (TCCC ASM)', 'HOLDING YOU! — спільний освітній проєкт «Повернись живим» та партнерів, який розгортає мережу мобільних навчально‑тренувальних комплексів із тактичної медицини на полігонах у різних регіонах України. Мета — щоб кожен військовослужбовець володів першою допомогою на рівні TCCC ASM, а інструктори мали обладнані класи, симуляційні манекени та навчальні набори для підтримки навичок у підрозділах. Фонд не лише закуповує наметові аудиторії з автономним живленням і опаленням, а й забезпечує їх мультимедійною технікою, витратними матеріалами, тренувальними турнікетами та симуляторами кровотеч. Паралельно готуються інструктори, які стандартизують навчання та масштабують його у Збройних Силах і інших складових Сил оборони. Кожна пожертва у цей проєкт — це інвестиція у «золоту годину» порятунку та зменшення бойових втрат. Фонд публікує факти й цифри реалізації та підтримує центри після запуску, що відповідає принципам прозорості й звітності благодійності. Завдяки донатам громадян і бізнесу «HOLDING YOU!» перетворює волонтерську підтримку на сталі навчальні спроможності, посилюючи оборону України та рятуючи життя на фронті й у прифронтових громадах.', 1),
(7, 'Power to Recover — адаптивний спорт для ветеранів', 'Power to Recover — ветеранська ініціатива «Повернись живим», зосереджена на реабілітації через адаптивний спорт. У партнерстві з відповідальним бізнесом проєкт забезпечує спортивним інвентарем і обладнанням тренування, змагання та клуби, створює доступ до регулярної активності й безпечного середовища відновлення для ветеранів і ветеранок по всій Україні. Цей напрям доповнює роботу Центру ініціатив Фонду, який розвиває культуру відновлення, проводить великі події на кшталт багатоденних національних змагань з адаптивних видів спорту, допомагає з підготовкою до міжнародних відборів і популяризує інклюзію. Пожертви благодійників спрямовуються на закупівлю інвентарю, логістику, організацію заходів і розвиток інфраструктури, а Фонд забезпечує прозорість і звітність щодо використання коштів. Проєкт мобілізує волонтерів, тренерів, місцеві спільноти й партнерів, змінюючи уявлення про повоєнну інтеграцію та доводячи, що благодійність — це не лише про техніку для фронту, а й про системну підтримку людей, які захищають Україну. Донати тут допомагають ветеранам повернутися до активного життя, відновити впевненість і знайти спільноту, що підтримує.', 1),
(8, 'Нам тут жити 2.0 — підтримка інженерних безпілотних систем для розмінування', '«Нам тут жити 2.0» — масштабний проєкт «Повернись живим» у партнерстві з національним оператором зв’язку, спрямований на прискорення гуманітарного розмінування та підвищення безпеки громадян. Ініціатива посилює роти інженерних безпілотних систем Сил підтримки ЗСУ роботизованими платформами, транспортом, зв’язком, живленням і дронами для ситуаційної обізнаності та дистанційного підривного розмінування. Завдяки поєднанню благодійних пожертв, корпоративної підтримки та інформаційного партнерства проєкт досяг заявленої цілі й був успішно реалізований, що підтверджено публічною звітністю. «Нам тут жити 2.0» показує, як волонтерська та донорська енергія може швидко нарощувати спроможності державних підрозділів у критично важливому для України напрямі — очищенні землі від вибухонебезпечних предметів, відновленні логістики, фермерства та базових сервісів у звільнених і прифронтових громадах. Прозорість і регулярні оновлення від Фонду дають благодійникам впевненість, що кожен донат спрямований за призначенням і рятує життя. Це приклад відповідальної благодійності, яка поєднує гуманітарну допомогу, технології та партнерства заради безпечної й відновленої України.', 1),
(9, 'Розвідувальні БПЛА', 'Напрям «Розвідувальні БПЛА» забезпечує підрозділи Сил оборони України сучасними дронами для аеророзвідки та коригування вогню. Команда фонду системно закриває офіційні запити військових, відбирає перевірені рішення, проводить закупівлі, логістику та передачу техніки безпосередньо у війська. У фокусі — безпечне отримання розвідданих, зменшення ризиків для особового складу, підвищення точності та швидкості прийняття рішень. Фонд постачає як мультикоптери для тактичної зйомки з малої висоти, так і БПЛА літакового типу для глибшого спостереження. До комплекту часто входять запасні акумулятори, станції живлення, засоби маскування, ПО для картографування й аналізу. Донати і пожертви від громадян та бізнесу перетворюються на конкретну підтримку на передовій, а прозорість і звітність забезпечуються окремими сторінками зі звітами. Важлива частина підходу — взаємодія з інструкторами та партнерами, щоб військові максимально ефективно використовували техніку. Це системна благодійність, де кожна гривня донатів працює на оборону України, а волонтери та команда фонду відповідають за якість, швидкість і відповідність реальним потребам підрозділів.', 2),
(10, 'Ударні БПЛА', 'Напрям «Ударні БПЛА» спрямований на посилення вогневих можливостей підрозділів за рахунок FPV-дронів, ударних БПЛА та бомберів. Фонд формує партії високоефективних рішень для різних завдань: ураження бронетехніки та укріплень, придушення ворожих позицій, перехоплення повітряних цілей. Закупівлі відбуваються під конкретні заявки, з урахуванням профілю бойових дій, доступності запчастин та придатності до нічних місій. Поруч із платформами забезпечуються системи керування, передавачі, корисні навантаження, навчальні матеріали для підрозділів. Благодійність у цьому напрямі має виражений прикладний ефект: кожен донат допомагає швидко перетворити кошти на реальні засоби ураження, що знижують ризики для штурмових груп і підвищують ефективність операцій. Команда фонду працює прозоро, звітує про закупівлі й видачу майна, підтримує зворотний зв’язок із частинами. Це послідовна підтримка оборони України, де пожертви, волонтери та партнерські виробники гуртуються заради спільної мети — захистити життя військових і наблизити перемогу.', 2),
(11, 'Радіоелектронна боротьба', 'Напрям забезпечення засобами радіоелектронної боротьби та розвідки посилює захист підрозділів від ворожих дронів і засобів зв’язку противника. Фонд закуповує й передає комплексні рішення для глушіння каналів керування, придушення передачі даних, виявлення джерел сигналів і перехоплення відеопотоків. Таке обладнання допомагає зменшувати втрати, зриває розвідоперації ворога, ускладнює застосування FPV-дронів по наших позиціях. Під час формування партій враховуються вимоги з фронту, умови застосування (мобільні чи стаціонарні комплекси), енергозабезпечення, а також сумісність з наявними системами частин. Благодійні донати та пожертви громадян і компаній конвертуються у технологічну перевагу, а звітність фонду дозволяє відстежувати використання коштів і передачу обладнання. У поєднанні з напрямами БПЛА та тактичної медицини це створює системний ефект: військові отримують не лише інструменти атаки та спостереження, а й надійний щит від ворожих засобів, що підсилює оборону України та зберігає життя захисників.', 2),
(12, 'Тактична медицина', 'Напрям «Тактична медицина» поєднує навчання бійців за сучасними протоколами TCCC та забезпечення підрозділів засобами домедичної допомоги. Команда інструкторів фонду проводить тренінги у максимально наближених до бойових умовах, відпрацьовуючи алгоритми Hemorrhage control, дії під час обстрілів, евакуацію поранених, роботу стабпунктів. Паралельно відбувається комплектація індивідуальних аптечок IFAK, постачання турнікетів, гемостатиків, перев’язувальних матеріалів, засобів для дихальних шляхів та евакуації. Благодійність тут має безпосередній вплив на виживання: кожен донат — це шанс врятувати життя побратима. Фонд підтримує професійну спільноту медиків і інструкторів через семінари та форуми, обмінюється кращими практиками, працює з партнерами зі сфери охорони здоров’я. Прозорість і звітність забезпечують довіру донорів і партнерів, а волонтери допомагають швидко доставляти комплекти та манекени для навчань. Усе це створює сталі спроможності підрозділів і підвищує готовність військ діяти у кризових ситуаціях, зміцнюючи оборону України та підтримку суспільства.', 2),
(13, 'Військова школа Боривітер', 'Фонд системно підтримує Військову школу «Боривітер», яка безоплатно навчає військовослужбовців за низкою ключових напрямів: від управління та планування до підготовки операторів БпЛА (мультироторних, літакового типу та FPV), зв’язку, ситуаційної обізнаності, топографії тощо. Співпраця фонду і школи дозволила масштабувати курси, посилити інструкторський склад, розробити навчальні програми та узгодити матеріально-технічну базу з реальними потребами фронту. Благодійні пожертви фінансують інфраструктуру навчань, закупівлю тренажерів, витратних матеріалів, засобів зв’язку та оптики для відпрацювання навичок. Завдяки цьому військові отримують не лише обладнання в межах інших напрямів фонду, а й потрібні компетенції, аби застосовувати його ефективно та безпечно. Така інтеграція підготовки і постачання техніки підвищує результативність підрозділів, скорочує час адаптації на передовій, а прозора звітність фонду та партнера формує довіру донорів і волонтерів. Це інвестиція у спроможності ЗСУ та довгострокову безпеку України.', 2),
(14, 'Центр Готовності Цивільних', 'Це всеукраїнська мережа осередків базової підготовки цивільних, створена фондом як відповідь на виклики повномасштабної війни. Учасники безкоштовно здобувають теоретичні та практичні навички: правила поводження зі зброєю, мінно-вибухову безпеку, домедичну допомогу, стрілецьку справу, основи аеророзвідки, користування оптикою, психологічну стійкість, підготовку до блекаутів і порядок дій під час тривог чи можливої мобілізації. Осередки працюють у багатьох містах, допомагаючи громадам підвищувати стійкість і самоорганізацію. Донати покривають витратні матеріали, навчальні манекени, мішені, оренду майданчиків та логістику інструкторів. Це приклад відповідальної благодійності, де волонтери, тренери й місцеве самоврядування діють разом. Прозорість та звітність фонду підсилюють довіру пожертводавців, а реєстрація на тренінги відкрита для всіх охочих. Проєкт зміцнює національну безпеку, розвиває культуру безпеки та підготовленості в Україні, підтримує громади на шляху до перемоги і відновлення.', 2),
(15, 'Проєкт із гуманітарного розмінування', 'Гуманітарний напрям фонду у сфері розмінування допомагає мобільним групам, що очищують деокуповані території від вибухонебезпечних предметів. Команда забезпечує саперів необхідною технікою: від транспортних засобів і засобів зв’язку до металодетекторів, інструментів для дистанційного підриву та механізованих платформ. Співпраця з профільними державними службами та громадами дозволяє сфокусувати ресурси на найбільш забруднених регіонах, пришвидшити темпи перевірки полів, доріг і соціальної інфраструктури. Благодійні пожертви й партнерські збори регулярно конвертуються у конкретні комплекси, човни для саперів, обладнання та витратні матеріали. Паралельно фонд підтримує інформаційні кампанії з мінної безпеки та залучає бізнес до цільових зборів, щоб посилити вплив і масштаб. Завдяки прозорій звітності донори бачать, як їхні донати перетворюються на гуманітарну допомогу, що рятує життя цивільних, відкриває шлях аграріям і комунальникам та повертає громадам базові умови для відновлення в Україні.', 2),
(16, 'Safe & Smart', 'Safe & Smart — гуманітарний проєкт фонду, спрямований на відновлення доступу дітей до офлайн і гібридного навчання під час війни через реконструкцію, облаштування та наповнення шкільних укриттів. Команда з партнерами проводить технічні обстеження, розробляє проєктну документацію, ремонтує комунікації, вентиляцію, виходи, підлоги та стіни, а також забезпечує меблі, техніку й елементи для дозвілля. В основі — дотримання актуальних норм для тимчасових захисних споруд і прозорі процедури співпраці з місцевими громадами. Благодійні донати, пожертви бізнесу та участь волонтерів перетворюються на видиму підтримку дітей, вчителів і батьків, а прозорість і звітність фонду допомагають будувати довіру. Проєкт не лише підвищує безпеку, а й зменшує освітню нерівність між регіонами, сприяє психологічній стійкості школярів і повертає громадам відчуття нормального життя навіть під час повітряних тривог. Це інвестиція у майбутнє України, реалізована через якісну гуманітарну допомогу, відповідальне партнерство та публічну звітність.', 2),
(17, 'СТРУМ — підписка безперебійного живлення бригади «Азов»', 'СТРУМ — це довгострокова програма регулярних пожертв АЗОВ.ONE, яка перетворює щомісячні донати на стабільне «живлення» для підрозділів бригади «Азов». Завдяки підписці волонтери та благодійники формують передбачуваний грошовий потік, що дозволяє планувати закупівлі наперед і оперативно закривати критичні запити без запуску окремих великих кампаній. Пожертви спрямовуються на невідкладні потреби: зв’язок і енергоживлення, засоби спостереження та протидії БпЛА, тактичне спорядження, транспорт, медичні комплекти та витратні матеріали. Програма розбудовує спільноту однодумців по всій Україні та за кордоном, пропонує прозорі правила, зрозумілу звітність і персональний кабінет для керування підпискою. Регулярні звіти надсилаються підписникам і публікуються на офіційних майданчиках, що підсилює довіру та прозорість. СТРУМ також розвиває партнерства з бізнесами й амбасадорами, створює реферальні можливості, заохочує популяризацію благодійності серед друзів і колег. Це не одноразовий збір, а сталий механізм підтримки оборони України, завдяки якому кожна системна пожертва перетворюється на реальну гуманітарну допомогу для захисників і збережені життя. У центрі — відповідальність перед донорами, прозорість процесів, публічна звітність і ефективність використання кожної гривні.', 3),
(18, '«Східний бар’єр» — масштабна кампанія АЗОВ.ONE і «Тиловиків»', '«Східний бар’єр» — це стратегічна кампанія АЗОВ.ONE спільно з проєктом «Тиловики», спрямована на зміну балансу на визначальних ділянках фронту. Ініціатива фокусується на забезпеченні бригади «Азов» засобами протидії загрозам із неба та інструментами для точних ударів у відповідь. Йдеться про комплексні рішення: сучасні системи радіоелектронної боротьби для захисту від ворожих БпЛА, розвідувальні та ударні дрони, обладнання зв’язку і спостереження, а також транспорт для мобільності підрозділів. Кампанія мобілізує волонтерів, благодійників і корпоративних партнерів із усієї України, заохочуючи регулярні донати та разові пожертви. У межах благодійності наголошується на прозорості: прогрес зборів і призначення витрат публікуються офіційно, що підсилює звітність і довіру спільноти. «Східний бар’єр» — це відповідь на ескалацію використання далекобійних дронів противником; завдяки централізованому фандрейзингу АЗОВ.ONE може швидко конвертувати підтримку громадян у реальні засоби посилення оборони. Проєкт покликаний довести, що об’єднані волонтери, системні донати та професійні закупівлі здатні суттєво впливати на безпеку захисників і цивільних, посилюючи оборону України на сході та формуючи надійний тил.', 3),
(19, '«Азов на зв’язку» — спільний збір із Obmify для захищених комунікацій', '«Азов на зв’язку» — цільова програма АЗОВ.ONE у партнерстві з Obmify, покликана забезпечити стабільні, захищені канали зв’язку для підрозділів бригади «Азов». У сучасній війні безперервна комунікація критична для координації дій, управління підрозділами та безпеки воїнів. Кампанія акумулює благодійні донати на закупівлю і впровадження обладнання зв’язку та мережевої інфраструктури, що підвищує стійкість до перешкод, кіберзагроз і радіоелектронних атак. Завдяки волонтерам і регулярним пожертвам донорів проєкт допомагає оновлювати парки засобів зв’язку, масштабувати канали резервування, забезпечувати польові пункти керування та підрозділи на передовій. Ініціатива підкреслює прозорість і звітність: ціль збору, статус і призначення витрат публікуються на офіційних сторінках, що дозволяє донорам бачити реальний вплив своєї підтримки. «Азов на зв’язку» демонструє, як адресна благодійність і колективні пожертви перетворюються на вимірюваний захист життя — від зменшення ризиків для бійців до підвищення ефективності операцій. Це приклад синергії громадянського суспільства, технічних партнерів і волонтерського сектору задля оборони України.', 3),
(20, 'Iron Cloud — електронна протидія ворожим дронам', 'Iron Cloud — фандрейзингова ініціатива АЗОВ.ONE, мета якої оснастити підрозділи бригади «Азов» сучасними системами радіоелектронної боротьби для протидії БпЛА противника. Проєкт підкреслює, що РЕБ — це оборонне, нелетальне обладнання, яке придушує канали зв’язку ворожих безпілотників, не дозволяючи їм коригувати вогонь чи завдавати ударів по техніці й особовому складу. Завдяки донатам благодійників АЗОВ.ONE закуповує перевірені рішення, оптимізуючи ціни та строки постачання, і оперативно доправляє їх на найгарячіші ділянки. Проєкт акцентує на прозорості: опис цілей, стан збору й призначення витрат оприлюднюються офіційно. Для волонтерів і меценатів це спосіб цілеспрямовано інвестувати у збереження життів захисників, адже потужні системи РЕБ — ключ до зниження втрат від FPV- та розвідувальних дронів. Iron Cloud — приклад того, як системні пожертви громадян і бізнесу можуть швидко перетворюватися на реальну перевагу на полі бою, підвищуючи живучість підрозділів і зміцнюючи оборону України.', 3),
(21, 'Shield the Brave — перша місія Міжнародного батальйону «Азову»', 'Shield the Brave — спеціальна кампанія АЗОВ.ONE на підтримку Міжнародного батальйону бригади «Азов», куди долучилися добровольці з США, Великої Британії, країн ЄС та інших держав. Ініціатива збирає благодійні донати на критичне нелетальне забезпечення: комплекти антидронового захисту (включно з потужними системами РЕБ і захисними накидками), тепловізійні приціли та тепловізори, далекоміри, а також польові рішення енергоживлення (зарядні станції та генератори). Пожертви дають змогу швидко доукомплектувати підрозділ перед розгортанням, підвищити його стійкість до ворожої аеророзвідки і FPV-загроз та забезпечити автономність у складних умовах. Кампанія підкреслює відкритість і підзвітність: опис потреб і способів підтримки доступний офіційно, з різними варіантами переказів для благодійників з України та з-за кордону. «Shield the Brave» показує, як міжнародна солідарність і волонтерський рух поєднуються в ефективну підтримку оборони України — від кожного доната до конкретних засобів на передовій.', 3),
(22, '«Сталевий кур’єр» — українські наземні роботизовані комплекси TARGUN', '«Сталевий кур’єр» — цільова кампанія АЗОВ.ONE, що передбачає забезпечення бойових підрозділів «Азову» українськими наземними роботизованими комплексами TARGUN. Такі платформи підсилюють підрозділи в умовах насиченого БпЛА поля бою, де дистанційність, автономність і точність виконання завдань мають критичне значення. Проєкт демонструє, як благодійність створює запит на інновації «made in Ukraine»: донати й пожертви від громадян і бізнесу прискорюють впровадження технологій, зменшують ризики для особового складу та підвищують ефективність логістики і вогневих дій. АЗОВ.ONE забезпечує прозорість збору, публікує статус та підсумки, звітує про призначення коштів. Кампанія стала прикладом синергії волонтерського руху, виробників і професійної команди фандрейзерів: завдяки злагодженій співпраці пожертви втілюються у реальні системи на фронті. Проєкт посилює довіру до механізмів публічної звітності й демонструє, як кожен внесок робить оборону України технологічнішою та безпечнішою.', 3),
(23, '«Тиловики 4. Місія “Мотанки Азову”» — волоконно-оптичні ударні БпЛА', '«Тиловики 4» — наступний етап відомої волонтерської ініціативи «Тиловики», який реалізовано разом з АЗОВ.ONE для підтримки бригади «Азов». Місія спрямована на забезпечення підрозділів волоконно-оптичними ударними безпілотниками «Мотанки Азову», що дозволяють вести розвідку і завдавати точних уражень зі зниженими ризиками РЕБ-пригнічення. Кампанія об’єднує широке коло доброчинців: від індивідуальних донаторів до компаній, які системно підтримують оборону України. Проєкт показує, як цільовий фандрейзинг перетворює пожертви на високотехнологічні рішення з вимірюваним впливом на полі бою. На офіційних ресурсах доступні деталі місії та результати, що підкреслює прозорість і підзвітність перед спільнотою. «Тиловики 4» — приклад того, як послідовна волонтерська робота та взаємодія з професійною командою закупівель забезпечують швидке постачання необхідних систем у війська, зберігають життя бійців і посилюють обороноздатність України.', 3),
(24, 'STALKER — збір на потреби 1-го батальйону бригади «Азов»', 'STALKER — це тематична благодійна кампанія АЗОВ.ONE для забезпечення 1-го батальйону 12-ї бригади спеціального призначення «Азов», створена у співпраці з ігровою спільнотою S.T.A.L.K.E.R. Ініціатива зосереджена на практичних потребах підрозділу: засобах РЕБ для захисту техніки від ворожих БпЛА, системах зв’язку, оптиці й тепловізійних прицілах, квадрокоптерах для розвідки, а також на необхідному транспорті та допоміжному обладнанні. Кампанія поєднує благодійність і популярну культуру, стимулюючи пожертви через розіграші тематичних винагород від партнерів. Завдяки цьому вдається залучати нову аудиторію донорів, підсилювати волонтерський рух і збільшувати обсяги підтримки. Пріоритет — прозорість і довіра: призначення збору та його хід публікуються офіційно, а команда АЗОВ.ONE забезпечує швидкі закупівлі й доставку на передову. STALKER демонструє, як сучасні комунікації й креативні формати допомагають мобілізувати сталі донати для конкретного підрозділу, перетворюючи кожну пожертву на вимірювану допомогу обороні України.', 3),
(25, 'Армія дронів', '«Армія дронів» — флагманська оборонна ініціатива, яку UNITED24 розгортає спільно з державними партнерами для системного забезпечення Сил оборони сучасними безпілотними авіаційними комплексами, підготовки пілотів і підтримки ремонтної інфраструктури. Кампанія об’єднує донорів, бізнес, волонтерів і амбасадорів, щоб перетворити благодійність на відчутну перевагу на полі бою. Завдяки прозорим процесам збору та звітності кошти спрямовуються на актуальні потреби підрозділів: від розвідки та коригування вогню до евакуації та протидії ворожим БпЛА. Проєкт передбачає як донати, так і передачу готових дронів, що робить участь доступною для кожного. UNITED24 регулярно публікує новини про партнерства, результати закупівель і навчання, підкреслюючи підзвітність та ефективність використання пожертв. «Армія дронів» — це символ об’єднання світу довкола України, коли пожертви швидко перетворюються на технологічну перевагу, рятують життя та зміцнюють оборону країни.', 4),
(26, 'Флот морських дронів', 'Флот морських дронів — це масштабний проєкт UNITED24, спрямований на посилення безпеки українського узбережжя та захист мирних міст від ракетних атак із моря. Кампанія акумулює благодійні донати на закупівлю безпілотних катерів зі спеціальним зв’язком, системами автопілотування та нічного бачення, а також на створення інфраструктури управління й зберігання. Мета ініціативи — забезпечити постійну присутність «очей і щита» на морі, що знижує ризики для цивільного судноплавства і підтримує гуманітарну безпеку. UNITED24 розгортає партнерські збори, креативні кампанії та колаборації, щоб залучати пожертви по всьому світу, поєднуючи волонтерів, бізнес і культуру. Прозорість забезпечується офіційними оновленнями і звітністю, що формує довіру донорів. Флот морських дронів став символом інноваційної оборони України, коли кожна пожертва допомагає створювати реальну морську відсіч агресору, роблячи благодійність і підтримку максимально прикладними та результативними.', 4),
(27, 'Операція «Єдність» (у т.ч. «Єдність‑2» — Новорічний салют)', '«Операція «Єдність» — це спільна кампанія UNITED24 з партнерами, яка мобілізує пожертви на закупівлю великої партії FPV‑дронів із боєкомплектом для підрозділів на найгарячіших ділянках фронту. Проєкт поєднує державну платформу, провідні благодійні організації та фінтех‑партнерів, демонструючи, як цільові збори за короткий час перетворюються на конкретні засоби посилення оборони. Продовженням став збір «Операція «Єдність‑2». Новорічний салют», покликаний швидко закрити критичні запити бригад. Комунікації кампанії побудовані на прозорості, публічних цілях і підзвітності, що дає донорам упевненість у результаті кожного внеску. «Єдність» підкреслює силу солідарності волонтерів, бізнесу й громадян, які через благодійність та регулярні донати підтримують Україну технологіями, необхідними для порятунку життів і стримування агресії. Це приклад того, як масові пожертви, грамотна звітність і швидка логістика трансформуються в тактичну перевагу на полі бою.', 4),
(28, 'Напрям UNITED24: Гуманітарне розмінування', 'Гуманітарне розмінування — один із п’яти ключових напрямів UNITED24, що фокусується на залученні благодійних донатів для забезпечення саперів технікою, обладнанням і засобами безпеки. Мета — зробити українські території безпечними для повернення людей, відновлення інфраструктури та нормального життя громад. UNITED24 публікує профільні звіти, показує пріоритети закупівель і розгортає цільові збори на очищення лікарень, шкіл, парків, лісів та інших об’єктів, де мінна небезпека щоденно загрожує цивільним. Прозорість і підзвітність підтверджуються регулярними оновленнями та аудитом, що підсилює довіру донорів із різних країн. Цей напрям критично важливий для гуманітарної допомоги та відбудови, адже кожен метр розмінованої землі — це врятовані життя і швидше відновлення економіки. Пожертви, великі й малі, перетворюються на конкретні інструменти для команд розмінування, а підтримка волонтерів і партнерів створює довгостроковий ефект для безпеки України.', 4),
(29, 'Програма «Відбудова України»', '«Відбудова України» — стратегічна програма UNITED24, спрямована на залучення пожертв для відновлення житлових будинків, соціальних об’єктів та критичної інфраструктури у постраждалих громадах. Платформа запускає цільові збори для відновлення квартирних будинків, шкіл і мостів, поєднуючи державні інституції, місцеві громади, бізнес і волонтерів. UNITED24 підкреслює прозорість: у новинах і звітах висвітлюються пріоритети, перебіг робіт і вплив на життя людей. Програма показує, як благодійність і регулярні донати трансформуються в конкретні проєкти, куди можуть повернутися тисячі українців. Окремі комунікаційні ініціативи мотивують спільноту робити внески на відбудову шкіл та культурних об’єктів, зберігаючи тяглість освіти та соціального життя. «Відбудова України» — це довгострокова підтримка, що відновлює гідність і безпеку громад, забезпечуючи прозору звітність і відчутний результат кожної пожертви.', 4),
(30, 'Напрям UNITED24: Медична допомога', '«Медична допомога» — базовий напрям UNITED24, який акумулює благодійні внески на закупівлю обладнання для порятунку життів, реабілітації постраждалих, медичного транспорту та резервного енергоживлення для лікарень. Платформа регулярно публікує імпакт‑звіти і новини про закупівлі, демонструючи прозорість і підзвітність перед донорами. Кампанії цього напряму підтримують лікарні по всій Україні: від генераторів і систем життєзабезпечення до реанімобілів і спеціалізованих автівок для евакуації поранених. До зборів долучаються міжнародні партнери, бізнес і волонтери, що підсилює сталість допомоги. Кожна пожертва — це вклад у безперервність медичних послуг в умовах війни, у безпеку операційних та реанімацій, у збереження здоров’я пацієнтів і персоналу. Завдяки чіткій звітності донори бачать реальний вплив своїх донатів на систему охорони здоров’я України та на життя конкретних людей.', 4),
(31, 'Bring Light Back to Ukrainian Schools (Повернути світло українським школам)', 'Bring Light Back — спеціальна освітня кампанія UNITED24, мета якої — забезпечити українські школи автономними генераторами, щоб навчання тривало навіть під час блекаутів та атак на енергетичну інфраструктуру. Ініціативу підтримують відомі амбасадори, ігрова індустрія та небайдужі донори зі всього світу. Кампанія має окрему ціль і прозору комунікацію результатів, що підсилює довіру та мотивує робити пожертви з будь‑якої країни. UNITED24 поєднує фандрейзинг із розіграшами, партнерськими активностями та сторітелінгом про вплив донатів на дітей і вчителів. Збір спрямований на гуманітарну допомогу в освіті, адже світло та тепло — базові умови безпеки й психологічної стійкості школярів. Кожен внесок перетворюється на конкретне обладнання для конкретної школи, а регулярна звітність демонструє ефективність витрат. Це приклад того, як благодійність і волонтерська підтримка напряму змінюють життя громад та майбутнє України.', 4),
(32, 'UNITED24 App і підтримка підрозділів у межах «Лінії дронів»', 'UNITED24 App — цифровий проєкт платформи, що дає змогу донорам напряму підтримувати елітні підрозділи безпілотних систем у межах флагманської ініціативи Президента України «Лінія дронів». У застосунку можна обрати підрозділ, оформити разовий або регулярний донат і відстежувати вплив у режимі реального часу: новини з фронту, виконані збори, подяки й фото‑ та відеозвіти. Така прозорість і звітність підсилюють довіру до благодійності й роблять пожертви максимально адресними. UNITED24 регулярно повідомляє про придбані дрони та обладнання, що оперативно надходять на позиції, — це демонструє ефективність моделі «донор → підрозділ». Проєкт поєднує гуманітарну та оборонну підтримку, мобілізуючи світову спільноту, волонтерів і бізнес до системної допомоги Україні. Завдяки застосунку донати перетворюються на конкретні технології, які рятують життя та посилюють захист держави.', 4),
(33, 'Герої районів', '«Герої районів» — всеукраїнська благодійна кампанія, яку штабний фонд «Підтримай Третю Штурмову» реалізує спільно з партнерами. Суть ініціативи — залучити мешканців усіх областей України до адресної підтримки бійців, що походять із їхнього рідного краю. Донори обирають «свій» район і спрямовують пожертви на нагальні потреби підрозділів: безпілотники, засоби радіоелектронної боротьби, зв’язок, паливо, бронетехніку та інше життєво необхідне оснащення. Такий підхід підсилює відчуття причетності, а також пришвидшує конвертацію донатів у реальну допомогу на фронті. Кампанія інтегрована з інструментами банківського сервісу, що робить внески зручними для громадян та бізнесу, а також прозорими — фонд публікує звітність і працює за офіційними реквізитами. Проєкт поєднує волонтерів, місцеві спільноти та великих партнерів задля сталої підтримки оборони України. Це широка комунікаційна платформа, яка мотивує регулярні донати, підсилює гуманітарну допомогу та нагадує: кожен район має свого героя, якого можна й потрібно підтримати саме сьогодні, зберігаючи прозорість і довіру до благодійності.', 5),
(34, 'За маму. За тата. За Третю штурмову', 'Це всеукраїнська фуд-кампанія, у межах якої заклади громадського харчування додають у меню спеціальну картопляну позицію, а прибуток від її продажу спрямовують на потреби 3-ї окремої штурмової бригади. Ініціатива об’єднує ресторани, кав’ярні й бари у різних містах, перетворюючи щоденні замовлення на системні пожертви. Гості впізнають учасників за характерною айдентикою та позначками у меню, а далі кожна порція — це маленький донат у велику спільну справу. Кампанія збирає на транспорт, дрони, енергоживлення та інші критично важливі речі, які підсилюють обороноздатність підрозділів на передовій. Формат простий і зрозумілий, тож доєднатися можуть і мережі, і локальні заклади: це про доступну благодійність, прозорі правила і колективну відповідальність бізнесу та громади. Команда фонду комунікує з партнерами, надає бренд-матеріали, публікує звітність, щоб кожен донор почувався впевнено, а зібрані кошти оперативно перетворювалися на гуманітарну допомогу, спорядження та підтримку військових України.', 5),
(35, 'Щомісячна підписка', 'Програма «Щомісячна підписка» запроваджена для тих, хто хоче допомагати регулярно та передбачувано. Кожен благодійник сам обирає суму, яка автоматично перераховується щомісяця на забезпечення 3-ї ОШБр. Такий формат створює стабільний грошовий потік для планових закупівель: спорядження, засобів зв’язку, дронів, комплектів захисту, енергообладнання та іншої гуманітарної допомоги. Підписники отримують символічні подяки від фонду, а головне — впевненість, що їхні пожертви працюють без пауз і затримок. Фонд надає офіційні реквізити, підтримує різні способи оплати та дотримується принципів прозорості й звітності: на сайті публікуються оновлення, а команда волонтерів у тісній координації з підрозділами пріоритезує витрати на найнагальніші потреби. Це зручний інструмент для громадян і бізнесу, який перетворює добру волю на сталу підтримку України, економить час донорів і водночас рятує життя завдяки безперервному постачанню необхідного на фронт.', 5),
(36, 'Зимова тисяча', '«Зимова тисяча» — окрема благодійна кампанія фонду, яка закликає українців спрямувати частину державного кешбеку на посилення медичної евакуації військових. Механіка проста: громадяни отримують кошти на спеціальну банківську картку і можуть добровільно пожертвувати їх на фонд для закупівлі бронетранспортерів евакуації та спорідненого обладнання. Ця ініціатива поєднує масові мікродонати в один потужний ресурс, що напряму впливає на збереження життів поранених: бронемашини швидко вивозять із-під обстрілів, забезпечують першу допомогу під час руху, підвищують безпеку екіпажу. Фонд надає докладні інструкції, офіційні реквізити та зручні канали донату, а також підкреслює прозорість використання коштів. Кампанія формує культуру відповідального донорства взимку, коли потреба в техніці та енергоживленні зростає, і водночас залучає до благодійності нові аудиторії, для яких важлива зрозуміла мета, швидкість впливу та довіра до волонтерів і звітності.', 5),
(37, 'Мережа Трійки', '«Мережа Трійки» — технологічний збір у партнерстві з українською IT-спільнотою DOU. Мета — забезпечити підрозділи сучасними комплексами, створеними інженерами Трійки, які поєднують безпілотні платформи, ретранслятори та «розумне» програмне забезпечення з елементами автономної навігації. Така мережа підсилює стійкість зв’язку та дозволяє працювати в умовах активної РЕБ, що критично важливо для штурмових дій і розвідки. Кампанія мобілізує айті-галузь: компанії та спеціалісти роблять донати, поширюють інформацію, а частину внесків заохочують призами від партнерів екосистеми. Це приклад соціальної відповідальності бізнесу, де інновації напряму зміцнюють оборону України. Фонд комунікує щодо потреб, забезпечує офіційні способи пожертв і публічність рішень, а спільнота DOU дає масштаб і швидкість збору. Разом це створює ефект «технологічного мультиплікатора», коли кожен донат перетворюється на реальну тактичну перевагу бійців.', 5),
(38, 'На ремонт бойової техніки (безстроковий збір)', 'Безстроковий напрям «На ремонт бойової техніки» покриває постійні витрати на відновлення автомобілів, бронемашин та іншого транспорту, що щодня працює в екстремальних умовах. Техніка зношується через уламки, обстріли, бруд, погоду — і її треба швидко повертати у стрій. Фонд відкрив окремі канали для пожертв: банківські перекази, картки, PayPal, криптогаманці та спеціальні банківські «банки», аби кожному донору було зручно допомогти. Регулярні донати дають змогу оперативно купувати запчастини, шини, мастила, оплачувати ремонтні роботи й логістику. Команда публікує звіти, у тому числі платіжні документи, що підсилює прозорість і довіру до благодійності. Завдяки волонтерам і небайдужим українцям відновлена техніка знову виконує бойові завдання, підвищуючи мобільність підрозділів, рівень безпеки й ефективність гуманітарної допомоги. Це один із найкритичніших напрямів підтримки, який напряму впливає на живучість і темп операцій 3-ї ОШБр.', 5),
(39, 'FPV‑штурм', '«FPV‑штурм» — масштабна ініціатива волонтерських центрів фонду, що організована за командним принципом у різних містах. Мета — забезпечити підрозділи достатньою кількістю FPV‑дронів для точних ударів по техніці та позиціях ворога. Фонд надає зрозумілий алгоритм дій: місцеві координатори запускають збори, об’єднують бізнеси й громаду, поширюють комунікаційні матеріали, а донори обирають зручний спосіб переказу. Така модель дозволяє швидко масштабувати збір: без зайвої бюрократії, але з дотриманням стандартів прозорості та звітності. FPV — одна з ключових технологій сучасної війни, тож кожна пожертва відгукується на полі бою вже сьогодні. Кампанія спрямована на постійну підтримку операторів і підрозділів розвідки, що підсилює оборону України й знижує ризики для особового складу. Це приклад того, як волонтери, громадські ініціативи та малі бізнеси через регулярні донати створюють значущий ефект на тактичному рівні.', 5),
(40, 'Великий збір на бронезахист', 'Ціль цього великого напряму — укомплектувати бійців сучасним бронезахистом, розробленим за уроками реальних бойових дій. У центрі проєкту — новий український бронежилет, створений у співпраці профільних виробників, який поєднує анатомічну посадку, посилену бокову та фронтальну зони, використання сучасних матеріалів і продуману ергономіку. Рішення розроблене з урахуванням досвіду оборонців Маріуполя та інших гарячих напрямків: воно покликане підвищити живучість і зручність під час штурмів, тривалих виходів і роботи в окопах. Завдяки донатам фонд централізовано закуповує комплекти, передає їх у підрозділи, комунікує з командирами та коригує пріоритети закриття заявок. Акцент робиться на прозорість процесу, публічні звіти і швидку логістику, щоб пожертви людей і бізнесу якнайшвидше ставали реальним захистом. Кампанія показує, як благодійність і волонтери здатні впливати на стандарти спорядження, зміцнюючи оборону України щоденними внесками.', 5),
(41, 'ОХМАТДИТ Київ – Відбудова після ракетної атаки', 'Проєкт спрямований на відбудову пошкодженого лікувально-діагностичного комплексу НДСЛ «Охматдит» у Києві після ракетної атаки. Благодійний фонд «ОХМАТДИТ – Здорове дитинство» координує збір пожертв і донатів від громадян, бізнесу та міжнародних партнерів, забезпечує прозорість рішень і публічну звітність, а також супроводжує ключові етапи відбору підрядників і виконання робіт. Мета ініціативи — якнайшвидше відновити критичну інфраструктуру дитячої лікарні, щоби маленькі пацієнти з усієї України знову могли безпечно отримувати високоспеціалізовану допомогу. У фокусі — підвищення стійкості медичного закладу, модернізація інженерних систем і створення безпечних умов для дітей та медперсоналу. Фонд наголошує на відкритій комунікації, публікації рішень щодо тендерів та партнерств, що підсилює довіру донорів і волонтерів. Це приклад відповідальної благодійності та гуманітарної допомоги, яка спрямована на довгострокову підтримку системи охорони здоров’я й укріплення дитячої медицини в Україні, із чіткими процедурами контролю, звітності та прозорості використання пожертв.', 6),
(42, 'Проєкт «Ментального здоровʼя дітей та підлітків» в поліклініці «Охматдит»', 'Ініціатива створює у київській поліклініці «Охматдит» безпечний простір для дітей та підлітків, де вони можуть своєчасно отримати психологічну та психіатричну допомогу без стигми, страху й довгого очікування. Фонд системно залучає благодійні донати, вибудовує партнерства та інфраструктуру допомоги, щоб розширити доступ до якісних послуг з ментального здоров’я. Проєкт передбачає облаштування дружніх до дитини кабінетів, забезпечення сучасними інструментами для оцінки стану, інтеграцію мультидисциплінарного підходу й посилення спроможності команди фахівців. Велика увага приділяється етичним стандартам, конфіденційності та прозорості витрачання коштів, що відображається у публічних оновленнях і звітності фонду. Ініціатива посилює стійкість родин, допомагає долати наслідки війни та стресу, підтримує підлітків у кризових ситуаціях. Це вклад благодійної спільноти у формування культури турботи про психічне здоров’я дітей в Україні, де кожна пожертва перетворюється на реальні інтервенції підтримки.', 6),
(43, 'Біохімічний аналізатор Selectra Pro M для лабораторії дитячої лікарні «Охматдит» у Львові', 'Проєкт передбачає оснащення львівської дитячої лікарні «Охматдит» сучасним біохімічним аналізатором Selectra Pro M — надійним інструментом для швидкого та точного визначення показників крові у дітей. Завдяки благодійним пожертвам та партнерській підтримці, лабораторна діагностика стає оперативнішою, що скорочує час очікування результатів і допомагає лікарям швидше ухвалювати клінічні рішення. Це підвищує якість лікування, зменшує тривожність батьків, а для медиків означає стабільні результати без зайвого ручного навантаження. Ініціатива є складовою ширшої місії фонду — зміцнювати дитячу медицину по всій Україні, розвиваючи мережу лікарень через адресні закупівлі критично потрібного обладнання. Фонд діє прозоро, комунікує мету збору, умови використання коштів і дотримується принципів звітності перед донорами та волонтерами. Так благодійність перетворюється на практичну гуманітарну допомогу, що безпосередньо підвищує спроможність регіональних закладів охорони здоров’я.', 6),
(44, 'Віртуальний координаційний центр рідкісних захворювань (Rare Disease Hub Ukraine)', 'HUB — це віртуальний координаційний центр, створений фондом у взаємодії з міжнародними партнерами для підтримки пацієнтів з орфанними хворобами. Команда залучає фахівців НДСЛ «Охматдит» і допомагає родинам орієнтуватися у маршруті лікування: від початкового запиту — до пошуку профільної клініки, спеціалістів в Україні чи за кордоном, збору документів і комунікації з медичними установами. Центр надає консультаційну й навігаційну допомогу, зменшує інформаційний бар’єр, сприяє своєчасній діагностиці та доступу до терапії, що критично важливо для рідкісних станів у дітей. Завдяки донатам і пожертвам підтримується безперервність роботи HUB і залучення експертів, а прозора звітність фонду зміцнює довіру благодійників. Проєкт також розвиває партнерства з європейськими мережами, поширює кращі практики та підсилює спроможність української системи охорони здоров’я відповідати на складні виклики дитячої орфанної патології, залишаючись прикладом гуманітарної підтримки і солідарності в Україні.', 6),
(45, 'Медичне обладнання для Київської обласної дитячої лікарні (м. Боярка)', 'У межах цього проєкту фонд забезпечив Київську обласну дитячу лікарню (Боярка) сучасним обладнанням для моніторингу стану маленьких пацієнтів і підвищення безпеки анестезії та інтенсивної терапії. Зокрема, заклад отримав приліжкові монітори для безперервного контролю життєвих показників, системи відстеження функцій мозку під час наркозу та модулі регіонарної оксиметрії для своєчасного виявлення дефіциту кисню в критично важливих органах. Це сприяє прийняттю лікарями оперативних рішень і знижує ризики у складних клінічних випадках. Ініціатива стала можливою завдяки благодійним пожертвам людей та бізнесу, які довіряють підходу фонду до прозорості, звітності та ефективного використання ресурсів. Проєкт є показовим прикладом гуманітарної допомоги, що напряму посилює спроможність регіональної дитячої медицини в Україні, а також демонструє, як волонтери, донори та партнерські організації об’єднуються задля реального впливу на якість лікування дітей.', 6),
(46, 'Проєкт «12 друзів Охматдиту»', 'Благодійно-мистецька кампанія, що поєднує історії пацієнтів «Охматдиту» та творчість українських амбасадорів. У межах проєкту створюються лімітовані арт-об’єкти «Бравий Котик», натхненні ескізами дітей. Вуличні інсталяції й стікери з QR-кодами запрошують перехожих долучитися донатом, а кульмінацією стає благодійний аукціон, де презентують унікальні скульптури. Кампанія підвищує обізнаність про потреби дитячої медицини та перетворює благодійність на залучальний культурний досвід. Фонд забезпечує прозору комунікацію мети зборів і використовує публічну звітність, що формує довіру донорів і партнерів. «12 друзів Охматдиту» — це яскравий приклад сучасної фандрейзингової ініціативи в Україні, де пожертви напряму підтримують лікування дітей, а волонтери й митці стають провідниками змін, об’єднуючи спільноту навколо конкретних історій мужності, надії та відновлення.', 6),
(47, 'Благодійний пробіг під каштанами разом з лікарями НДСЛ «Охматдит»', 'Щорічна спортивно-благодійна подія, мета якої — зібрати пожертви на потреби відділень НДСЛ «Охматдит» та залучити громаду до підтримки дитячої медицини. Пробіг об’єднує лікарів, волонтерів, благодійників і небайдужих громадян, перетворюючи кроки учасників на реальну гуманітарну допомогу. Фонд забезпечує прозору організацію зборів, публічно оголошує напрямок використання донатів і звітує про результати, що посилює довіру і мотивує бізнес та громаду долучатися щороку. Подія водночас популяризує культуру благодійності в Україні, а зібрані кошти спрямовуються на конкретні закупівлі обладнання та поліпшення умов лікування. Ініціатива показує, як спільні зусилля — від невеликої пожертви до корпоративної підтримки — допомагають лікарні системно вирішувати нагальні потреби та покращувати результати лікування дітей. Це приклад ефективної комунікації, залучення нових донорів і відповідальної звітності у сфері медичної благодійності.', 6),
(48, 'Сучасний операційний стіл для відділення пластично-реконструктивної мікрохірургії НДСЛ «Охматдит»', 'Адресний проєкт із забезпечення відділення пластично-реконструктивної мікрохірургії сучасним операційним столом, що підвищує безпеку та комфорт під час тривалих втручань у дітей. Завдяки благодійним пожертвам фонд придбав обладнання, яке допомагає зменшувати ризики ускладнень, поліпшує умови роботи хірургів і пришвидшує відновлення пацієнтів. Ініціатива є частиною ширшої стратегії фонду щодо модернізації операційних і забезпечення лікарів інструментами, що відповідають сучасним стандартам дитячої хірургії. Публікації фонду фіксують результати проєкту, що посилює прозорість і підзвітність перед донорами, волонтерами та партнерами. Таким чином благодійність трансформується у конкретні клінічні переваги: точність і стабільність під час мікрохірургічних операцій, покращення якості допомоги дітям і підвищення стійкості медичної системи України перед викликами воєнного часу.', 6),
(49, 'Flying Head: військовими для військових', 'Flying Head — це ветеранський проєкт, який Markus Foundation підтримує фінансово та організаційно для підсилення підрозділів Сил оборони України сучасними безпілотними рішеннями. Команда, створена колишніми бійцями 47 ОМБр, розробляє й виготовляє FPV-дрони, наземні станції та засоби радіоелектронної боротьби, тестує їх разом із військовими та оперативно допрацьовує під реальні бойові задачі. Такий підхід забезпечує високу ефективність кожної пожертви, адже донати спрямовуються на конкретні потреби війська — комплектуючі, збірку, налаштування та випробування. Проєкт уже взаємодіяв з підрозділами 47 ОМБр і 79 ОДШБр, що підтверджує практичну цінність розробок. Партнерство із фондом дозволяє швидко масштабувати виробництво, залучати волонтерів і благодійників, а також підтримувати прозорість і звітність використання коштів. Завдяки регулярним донаціям і партнерським кампаніям Flying Head перетворює благодійність на дієвий інструмент захисту життя українських воїнів, зміцнює обороноздатність, підвищує технологічну перевагу на полі бою та демонструє, як спільні пожертви громадян і бізнесу можуть давати вимірюваний результат для України.', 7),
(50, 'Лінія підтримки родин службовців 47 ОМБр', 'Markus Foundation організував окрему лінію підтримки для родин і близьких військовослужбовців 47 окремої механізованої бригади. Це постійно діюча програма допомоги, де можна отримати інформаційну та емоційну підтримку, записатися на консультацію до психолога, а також скоординувати звернення з практичних питань. Лінія працює у будні години, а у вихідні доступна у форматі месенджерів, що дозволяє швидко реагувати на запити. Така ініціатива зменшує навантаження на сім’ї захисників, допомагає їм орієнтуватися в бюрократичних процедурах і зберігати ресурс під час служби рідних. Програма вибудувана на засадах благодійності, відповідального волонтерства та турботи про спільноту, де прозорість і звітність є важливими цінностями фонду. Кожен донат на діяльність фонду опосередковано підсилює і цю лінію підтримки: завдяки пожертвам є можливість залучати фахівців, утримувати комунікаційну інфраструктуру та розвивати додаткові сервіси для сімей військових. Це реальна адресна допомога для України, яка підвищує стійкість громади бригади та зберігає мотивацію воїнів.', 7),
(51, 'Кампанія «Тримаймо Схід!» (дрони та РЕБ для підрозділів СОУ)', '«Тримаймо Схід!» — це цільова кампанія Markus Foundation на забезпечення підрозділів, які тримають напрямки на Донеччині та Харківщині. У межах ініціативи фонд збирає донати на розвідувальні дрони, FPV-платформи, тепловізійні квадрокоптери та засоби радіоелектронної боротьби для конкретних частин, серед яких 63 ОМБр, 122 окремий аеромобільний батальйон ДШВ, БТГр 169 (екіпаж ППО) та бригада НГУ «Спартан». Кампанія має прозору логіку: офіційний запит від підрозділу — закупівля — передача на баланс за актами — публікація матеріалів про виконання. У межах цієї програми вже реалізовано окремі проєкти поставок, зокрема передачу квадрокоптерів для 122 ОАеМБ. Пожертви від громадян і бізнесу конвертуються у техніку, яка допомагає зберігати життя, посилює розвідку, коригування вогню та захист від ворожих БпЛА. Кампанія фокусується на швидкості прийняття рішень, відповідальній звітності та партнерстві з волонтерами, що робить благодійність максимально ефективною для фронту і підсилює оборону України.', 7),
(52, 'Збір для ГУР та полку «NEMESIS» (ударні БпЛА)', 'Ця кампанія Markus Foundation спрямована на закупівлю ударних безпілотних систем для Головного управління розвідки Міністерства оборони України та полку ударних безпілотних систем «NEMESIS». Вона об’єднує донати тисяч благодійників, які перетворюються на високоточні засоби ураження та інші комплектуючі, необхідні для виконання складних бойових завдань: від точкових уражень техніки й логістики ворога до роботи БпЛА дальньої дії. Кампанія підкреслює важливість технологічної переваги, прозорих процесів і офіційних запитів від підрозділів, а також демонструє, як пожертви від людей і бізнесу можуть швидко закривати критичні потреби фронту. Усі деталі про мету збору, номенклатуру техніки та етапи реалізації подаються на офіційних сторінках фонду, завдяки чому донори бачать, як їхні внески працюють. Ініціатива підсилює взаємодію волонтерів, партнерів і виробників, а відтак — стійкість оборони України й захист життя військових.', 7),
(53, 'Збір для ГУР, «NEMESIS» та 47 ОМБр (ударні дрони + розіграш)', 'Масштабна кампанія фонду, у межах якої збираються кошти на ударні БпЛА для підрозділів ГУР МОУ, полку «NEMESIS» та 47 окремої механізованої бригади. Особливість цієї ініціативи — мотиваційний розіграш призів від співзасновника фонду, що залучає додаткову увагу до потреб фронту та стимулює регулярні донати. Мета збору — передати підрозділам перевірені бойові «робочі конячки»: FPV-дрони та інші ударні платформи, які підсилюють можливості розвідки, точних уражень і протидії ворожим БпЛА. Кампанія чітко описує призначення пожертв, підрозділи-одержувачі, а також наголошує на прозорих процедурах — від офіційного запиту до передачі на баланс за актами. Для благодійників це означає зрозумілий шлях кожної пожертви, швидку конвертацію донатів у техніку та регулярні оновлення щодо перебігу збору. Такі ініціативи допомагають масштабувати допомогу, активізують громаду волонтерів і посилюють оборону України завдяки синергії громадянського суспільства й військових.', 7),
(54, 'Партнерська ініціатива: благодійна футболка Creative Depo «Semper Audentes!»', 'Markus Foundation розвиває партнерські програми зі свідомим бізнесом, серед яких — благодійна футболка Creative Depo «Semper Audentes!». Увесь прибуток від продажу цього мерчу щомісяця перераховується на рахунок фонду й спрямовується на поточні потреби Сил оборони: закупівлю обладнання, засобів зв’язку, інструментів, а за потреби — і засобів радіоелектронної боротьби. Такий підхід створює стабільне джерело фінансування поза разовими зборами, дозволяє оперативно реагувати на термінові запити без пауз на оголошення нових кампаній і забезпечує сталість допомоги. Партнерство відкрито для інших компаній: фонд пропонує прозорі умови співпраці, чітку звітність і спільні інформаційні активності для залучення донорів. Покупець мерчу стає благодійником, а бізнес — надійним тилом для військових. Це приклад того, як цінності корпоративної соціальної відповідальності перетворюються на реальну підтримку України, коли кожна покупка — це пожертва, що допомагає зберігати життя наших захисників і захисниць.', 7),
(55, 'На ремонт бойової техніки', '«На ремонт бойової техніки» — безстроковий цільовий збір фонду Support AZOV, спрямований на оперативне відновлення та обслуговування транспорту і техніки підрозділів 3-ї окремої штурмової бригади. Умови фронту — уламки, кулі, бруд, вода, екстремальні перепади температур — щодня виводять із ладу пікапи, вантажівки, МТ- та спецтехніку. Завдяки благодійності та пожертвам волонтери фонду можуть швидко закуповувати запчастини, акумулятори, мастила, шини, витратні матеріали, оплачувати роботи СТО, евакуацію пошкоджених машин і польові ремонти. Кожен донат напряму конвертується у боєздатність підрозділів: мобільність груп, підвезення боєприпасів і води, евакуацію поранених, ротацію особового складу. Фонд надає кілька зручних способів підтримки (перекази в гривні й валюті, Monobank, PayPal, криптогаманці), а прозорість і звітність забезпечуються публікацією платіжних документів і оновлень на офіційних ресурсах. Це постійна програма допомоги, яка поєднує волонтерів, бізнес і громади України в одній меті — тримати техніку у строю та наближати перемогу завдяки відповідальній підтримці і підзвітному використанню коштів.', 8),
(56, 'На генератори та EcoFlow', 'Збір «На генератори та EcoFlow» закриває нагальну потребу підрозділів у надійному електроживленні на передовій. Дизельні генератори та портативні зарядні станції критично важливі для роботи пунктів управління, розгортання засобів зв’язку, живлення тепловізорів і приладів нічного бачення, заряджання батарей БПЛА, освітлення й обігріву бліндажів, а також функціонування медичних пунктів і ремонтних локацій. Благодійність і донати дозволяють фонду швидко купувати обладнання потрібної потужності, організовувати логістику, розподіл і пусконалагоджувальні роботи разом із військовими. Волонтери координують заявки безпосередньо з бойовими підрозділами, що гарантує адресність допомоги та економію часу. Фонд дотримується принципів прозорості й звітності: оновлення про передання, фото- та текстові звіти доступні на офіційних ресурсах. Кожна пожертва — це підтримка енергетичної стійкості оборонців України, зменшення залежності від атак по енергосистемі та реальний внесок громадян і бізнесу у зміцнення фронту. Таке обладнання працює щодня, рятує життя і забезпечує виконання бойових задач у будь-яку погоду.', 8),
(57, 'На засоби для побудови фортифікаційних споруджень', 'Проєкт «На засоби для побудови фортифікаційних споруджень» забезпечує бійців інструментами, необхідними для інженерного облаштування позицій. Першочергово йдеться про бензопили та сокири-колуни, що дають можливість швидко заготовляти колоди, зміцнювати окопи й бліндажі, будувати укриття, посилювати вогневі точки та маскувати техніку. Це не лише безпека, а й поліпшення побутових умов воїнів під час тривалих ротацій. Завдяки благодійності українців і міжнародних друзів фонд оперативно закуповує надійні інструменти, витратні матеріали, мастила й засоби догляду, а також забезпечує доставку на конкретні підрозділи. Координацію беруть на себе волонтери, що працюють у тісному контакті з 3-ю ОШБр. Підзвітність і прозорість — невід’ємна частина ініціативи: фонд публікує звіти про використання коштів і фотофіксацію передач. Кожен донат — це внесок у зміцнення лінії оборони України, що напряму зменшує втрати, підвищує стійкість позицій і допомагає виконувати завдання у складних погодних та бойових умовах.', 8),
(58, 'Великий збір на бронезахист', '«Великий збір на бронезахист» — масштабна кампанія фонду Support AZOV із забезпечення штурмовиків сучасними бронежилетами, створеними на основі реального бойового досвіду оборонців Маріуполя та «Азовсталі». Конструкція бронезахисту поєднує ергономічну розв’язку й високомолекулярний балістичний поліетилен, що дає високий рівень протикульного й протиосколкового захисту при збереженні мобільності бійця. Ініціатива спрямована на зменшення поранень у штурмових діях, комфортне носіння та сумісність із розвантажувальними системами, плитами й засобами зв’язку. Пожертви покривають закупівлю серійних комплектів, контроль якості, логістику на фронт і документальне приймання. Волонтери супроводжують процес від збору донатів до фактичної передачі на підрозділи. Вся діяльність прозора: звітність і підтвердження закупівель доступні на офіційних ресурсах. Завдяки підтримці громадян, бізнесу та діаспори ця благодійність перетворюється на реальний щит для захисників України, що підвищує їхню живучість і ефективність виконання бойових завдань.', 8),
(59, 'На снайперів 3-ї ОШБр на Бахмут', 'Цільовий збір «На снайперів 3-ї ОШБр на Бахмут» покликаний забезпечити снайперські підрозділи якісною оптикою та сошками. Сучасні оптичні приціли, надійні кріплення і стабільні опори суттєво підвищують точність ураження, скорочують витрату боєприпасів і дозволяють працювати на безпечніших дистанціях, підтримуючи піхоту та прикриваючи штурмові групи. Благодійні донати спрямовуються на закупівлю оптики, кронштейнів, сошок та супутніх аксесуарів, включно з кейсами й засобами догляду. Волонтери фонду координують технічні специфікації безпосередньо з підрозділом, аби допомога була адресною і відповідала тактичним задачам. Фонд дотримується принципів прозорості та звітності: пожертви приймаються зручними способами, а підтвердження передачі спорядження публікується на офіційних ресурсах. Завдяки підтримці громадян України, бізнесу та партнерів з-за кордону підвищується ефективність контрснайперської боротьби та загальна результативність виконання бойових завдань на одному з найгарячіших напрямків.', 8),
(60, 'Терміновий збір на східний напрямок', '«Терміновий збір на східний напрямок» — оперативна кампанія у відповідь на загострення бойових дій. Перелік потреб включає критично необхідні позиції: повнопривідні пікапи для мобільності та евакуації, квадрокоптери для розвідки і коригування, засоби зв’язку, джерела живлення (акумулятори та батарейки), техніку для облаштування командних пунктів (ноутбуки, великі екрани), а також засоби утеплення й польового побуту та мастильні матеріали для обслуговування транспорту. Проєкт поєднує військове оснащення і гуманітарну допомогу, щоб зберегти життя, підвищити стійкість і забезпечити безперервність управління підрозділами. Благодійність і донати дозволяють волонтерам фонду швидко консолідувати ресурси, закупити обладнання великими партіями та доставити його на передову. Прозорість і звітність підтверджуються офіційними оновленнями, що відображають статуси окремих пунктів. Кожна пожертва — це реальна підтримка оборони України у критичний час, коли оперативність наповнення збору безпосередньо впливає на хід бойових дій.', 8),
(61, 'Проєкт «Нічні привиди»', 'Проєкт «Нічні привиди» спрямований на посилення нічних спроможностей підрозділів завдяки приладам нічного бачення та лазерним цілевказівникам. Оснащення дає змогу бійцям ефективно діяти у темряві: проводити спостереження, непомітні переміщення, засідки й точні ураження, зменшуючи ризики для життя та підвищуючи результативність. Ініціатива реалізується за підтримки друзів зі США, які допомагають із придбанням і логістикою до України, тоді як фонд акумулює благодійні донати, забезпечує юридичний супровід, документальне приймання й відкриту комунікацію. Волонтери координують технічні специфікації, тестують перед відправкою, ведуть прозору звітність. Пожертви громадян, бізнесу та діаспори перетворюються на адресні комплекти НВП, що підсилюють боєздатність штурмових груп і загальну безпеку особового складу. Кампанія підкреслює прозорість, відповідальність і публічну підзвітність фонду та є прикладом міжнародної підтримки України, де кожен донат стає вкладом у захист життя й успіх завдань на передовій.', 8),
(62, 'На армійський броньовик', 'Кампанія «На армійський броньовик» покликана придбати захищений транспортний засіб для підвищення живучості та мобільності підрозділів 3-ї окремої штурмової бригади. Броньовик виконує критичні функції: доставка груп у зону бою, евакуація поранених, підвезення боєкомплекту і засобів зв’язку, розвідка на небезпечних ділянках. Благодійні пожертви покривають вартість машини, додаткового обладнання (радіостанції, маяки, інструменти), базове техобслуговування і підготовку до роботи в польових умовах. Волонтери фонду координують підбір моделі під завдання, документальне приймання, страхування та логістику до підрозділів. Прозорість і звітність — ключова умова довіри: фонд публікує оновлення про використання коштів і фактичну передачу техніки. Донати від громадян України, бізнесу та міжнародних партнерів прямо впливають на безпеку екіпажів, зменшення втрат і успіх завдань штурмових груп, перетворюючи підтримку на реальний ресурс фронту.', 8),
(63, 'Відділ роботи з пораненими', 'Відділ роботи з пораненими Патронатної служби «Янголи» — це безперервний супровід захисників від моменту поранення до повного відновлення або звільнення за станом здоров’я. Команда медичних кураторів координує лікування у військових і цивільних закладах по всій Україні, допомагає з додатковими обстеженнями, залученням вузьких спеціалістів, організацією реабілітації та, за потреби, протезуванням. Окремий напрям — документальний супровід: формування пакета довідок, консультації щодо проходження ВЛК, підготовка документів для встановлення статусів і виплат. «Янголи» також забезпечують бійців речами першої необхідності, координують гуманітарну допомогу та налагоджують комунікацію з родинами поранених. Це системна благодійність, яка спирається на донати і професійну волонтерську роботу. Служба наголошує на прозорості та регулярній звітності: публікує щомісячні звіти, відкрито пояснює структуру витрат, дякує партнерам і донорам. Завдяки постійному діалогу з лікарями, військовими структурами і громадськими організаціями, відділ перетворює пожертви на відчутну підтримку поранених воїнів, пришвидшуючи їхнє повернення до служби чи повсякденного життя. Ключові цінності — підтримка, людяність, ефективність, Україна понад усе.', 9),
(64, 'Відділ роботи у питаннях безвісти зниклих та полонених', 'Цей напрям Патронатної служби «Янголи» охоплює одразу кілька груп: захисників, які повернулися з полону; військових, що досі утримуються ворогом; безвісти зниклих; а також родини всіх перелічених категорій. Команда збирає та верифікує дані для розшуку й ідентифікації, моніторить ворожі ресурси, опрацьовує фото- та відеосвідчення, веде внутрішню базу інформації, оперативно передає матеріали до компетентних державних органів — Національного інформаційного бюро, Координаційного штабу з питань поводження з військовополоненими, СБУ, МВС. Фахівці допомагають родинам із юридичними питаннями, пояснюють алгоритми дій, супроводжують зміну статусів, підтримують у період очікування та після звільнення. Для тих, хто щойно вийшов з полону, «Янголи» організовують пакунки першої необхідності і термінові збори, щоб закрити базові потреби в перші 24 години. Це зразок адресної гуманітарної допомоги і водночас поле для партнерства волонтерів, донорів і держави. Робота відділу публічно висвітлюється у власних каналах комунікації та медіа, а прозорість забезпечується регулярною звітністю фонду і чіткими правилами обміну інформацією з державними структурами.', 9),
(65, 'Відділ роботи з полеглими та їхніми родинами', 'Відділ роботи з полеглими та їхніми родинами опікується всім, що потрібно для гідного прощання з Героями та підтримки близьких у найважчі дні. Команда взаємодіє з РТЦК та СП, органами досудового розслідування і профільними службами, координує транспортування тіла від місця евакуації до місця поховання, допомагає родині у вирішенні нагальних юридичних і організаційних питань. «Янголи» беруть на себе підготовку церемонії: оформлення місця поховання або кремації, залучення почесної варти, оркестру, хорунжої служби, комунікацію з підрозділом і врахування волі полеглого та побажань близьких. Окрема увага — збереженню пам’яті, підтримці родин і суспільному вшануванню. Це благодійність, що поєднує людяність та професійну організацію, а також прозорість — служба звітує про використання пожертв і публічно відстоює право на гідне вшанування Захисників України. Волонтери й донатори допомагають утримувати високі стандарти підтримки сімей і формувати культуру пам’яті, яка об’єднує країну.', 9),
(66, 'Відділ роботи з родинами військових', 'Цей відділ — про системну турботу і довгострокову підтримку родин воїнів Третьої окремої штурмової бригади та інших підрозділів азовського руху. «Янголи» організовують свята й культурні події для сімей, відправляють дітей до оздоровчих таборів, проводять семінари та творчі майстер-класи з елементами психологічної підтримки, допомагають оформлювати документи та вирішувати індивідуальні питання. Регулярні подарункові ініціативи до Різдва, Дня захисту дітей та інших подій перетворюють донати на конкретну радість і полегшення для сімей, що переживають війну. Команда співпрацює з державними й приватними партнерами, адвокатує зміни у законодавстві для кращого соціального захисту, а також дотримується принципів прозорості та звітності: благодійні пожертви і витрати відображаються у відкритих звітах. Це поєднання волонтерської емпатії, професійного менеджменту та гуманітарної допомоги, спрямованої на те, щоб сім’ї відчували опору держави, громади і благодійників по всій Україні.', 9),
(67, 'Медіа-відділ Патронатної служби «Янголи»', 'Медіа-відділ «Янголів» — це центр комунікацій, фандрейзингу і партнерств. Команда створює контент для соцмереж, організовує інтерв’ю, брифінги та пресконференції, готує інформаційні кампанії, запускає колаборації з українськими брендами та митцями, а також проводить благодійні заходи й навчальні курси. Одна з ключових місій відділу — перетворення донатів на цільову допомогу пораненим, родинам і ветеранам через чіткі збори та прозору звітність. Медіа-відділ формує впізнаваність служби, розповідає історії відновлення захисників, координує мерч-проєкти на кшталт Angels Club, підтримує репутацію відкритості і довіри. Саме через цей напрям волонтери, бізнес і благодійники швидко знаходять точку дотику: пожертви йдуть на лікування, реабілітацію, гуманітарну допомогу та організацію прощань, а суспільство отримує регулярні оновлення, підкріплені публічними звітами. Це команда, що будує міст між доброчинністю і реальними змінами для оборонців України.', 9),
(68, 'Angels Club – не просто мерч, а затишна спільнота друзів Патронатної служби', 'Angels Club — це лінійка благодійного мерчу, запущена у 2024 році як спосіб об’єднати друзів Патронатної служби «Янголи» навколо спільної мети: допомога пораненим, сім’ям та ветеранам. До колекції входять футболки з авторським принтом, патчі в різних кольорах, 3D-стікери, джибітси для кроксів і стікерпак, натхненний щоденною роботою служби. Купівля будь-якого з цих виробів — це пряма благодійність: кожна пожертва через мерч перетворюється на оплату лікування, реабілітації та інші нагальні витрати. Команда комунікує з покупцями відкрито, звітує про збори й закупівлі, залучає волонтерів і бізнес до колаборацій. Angels Club — не просто речі, а спільнота підтримки, де кожен донат посилює гуманітарну допомогу і де прозорість та звітність — невід’ємні цінності. Проєкт розвиває культуру відповідального споживання і сталих донорських практик в Україні, а кожне придбання наближає перемогу і повернення воїнів до повноцінного життя.', 9),
(69, 'Колаборація Патронатної служби та Mad Heads Coffee Roasters — Azov’s Angels Buddy', 'Azov’s Angels Buddy — перша велика колаборація «Янголів» з українським брендом Mad Heads Coffee Roasters, над якою команда працювала з березня по липень 2023 року. Проєкт поєднав благодійність, дизайн і любов до кави: створили окрему лінійку обсмаження зі спільним візуальним стилем і мерч — футболки, сталеві кружки, піни, стікери. Механіка проста і чесна: покупка кожної позиції дорівнює донату на лікування та відновлення поранених бійців, а самі продажі комунікувалися через відкриті публікації з деталями результатів. За даними служби, за 15 місяців продано майже 15 тонн кави (56 тисяч пачок) і зібрано понад 5 мільйонів гривень — це приклад того, як прозорі пожертви, відповідальна звітність і креативні партнерства здатні масштабувати підтримку. Колаборація стала дороговказом для наступних бізнес-ініціатив: кожен бренд, який долучається, допомагає системно, а волонтери отримують додатковий інструмент для фандрейзингу на користь оборонців України.', 9),
(70, '«Рятівний збір» на 30 млн', '«Рятівний збір» — масштабна благодійна кампанія Патронатної служби «Янголи», спрямована на оплату лікування й реабілітації поранених захисників. Наприкінці 2024 року команда оголосила нову хвилю зі стратегічною метою — 30 мільйонів гривень. Формат — командний: до ініціативи долучаються благодійники, бізнеси та лідери думок, відкриваються «допоміжні банки», проводяться благодійні події, а кожен донат стає внеском у повернення воїнів до повноцінного життя. Кампанія ведеться спільно з партнерською організацією, публічно оновлюється у соцмережах, має зрозумілі реквізити для пожертв і чітке цільове призначення коштів. ЗМІ повідомляли про значні суми, зібрані в межах цього збору, що підкріплює довіру до ініціативи. «Янголи» наголошують на прозорості: щомісячно звітують, відкривають доступ до чеків і пояснюють структуру витрат. Це приклад того, як волонтери, донори та український бізнес поєднують зусилля, перетворюючи благодійність і регулярні донати на системну підтримку оборонців України.', 9)
INSERT INTO public.problems (problem_id, name, context, content, is_processed, created_at) OVERRIDING SYSTEM VALUE VALUES
(1, 'Толерантність до воєнного злочинця', 'Людина висловлює обурення, що хтось позитивно відгукується пр…повідальність за війну в Україні та загибель мирних громадян.', NULL, TRUE, '2025-05-19 8:20:55'),
(2, 'Знецінення українських жертв', 'Пост підкреслює моральну неприйнятність хвалити людину, на ру…— кров українців. Це свідчить про глибоку травму суспільства.', NULL, TRUE, '2025-05-19 8:20:55'),
(3, 'Моральна апатія або необізнаність', 'Існує проблема, що окремі люди або не розуміють масштабів тра… або свідомо ігнорують їх. Це загострює розкол у суспільстві.', NULL, TRUE, '2025-05-19 8:20:55'),
(4, 'Сенсаційність у ЗМІ', 'Людина розчарована тим, що медіа не подає правдиву інформацію… а створює заголовки заради кліків, ігноруючи реальний зміст.', NULL, TRUE, '2025-05-19 8:20:55'),
(5, 'Викривлення фактів', 'Журналісти нібито доповнили матеріал подробицями, яких немає в оригіналі, маніпулюючи контекстом та довірою читачів.', NULL, TRUE, '2025-05-19 8:20:55'),
(6, 'Знецінення приватного життя', 'Критика також спрямована на втручання в особисте життя публічних осіб, без їхньої згоди, що порушує етичні норми.', NULL, TRUE, '2025-05-19 8:20:55'),
(7, 'Поверхневість аудиторії', 'Автор посту згадує читачів, які не читають саму статтю, але емоційно реагують — це проблема загального зниження критичного мислення.', NULL, TRUE, '2025-05-19 8:20:55'),
(8, 'Байдужість педагогів до дітей', 'Пост викриває неспроможність вчителів співпереживати та емоційно підтримувати учнів, які перебувають у кризовому стані.', NULL, TRUE, '2025-05-19 8:20:55'),
(9, 'Невиконання виховної функції школи', 'Автор вважає, що вчителі мають не лише вчити, а й займатись морально-етичним вихованням — але цього не відбувається.', NULL, TRUE, '2025-05-19 8:20:55'),
(10, 'Психологічна травматизація дітей', 'Відсутність належної уваги може лише поглибити травму, а безпорадність дорослих — підсилити відчуття ізоляції у дитини.', NULL, TRUE, '2025-05-19 8:20:55'),
(11, 'Критика системи освіти', 'Присутній гнів на всю освітню систему, яка продукує байдужих працівників — що свідчить про глибше соціальне невдоволення.', NULL, TRUE, '2025-05-19 8:20:55'),
(12, 'Втрачена повага до батьків', 'Людина засмучена, що діти не цінують жертви своїх батьків, навіть коли ті рятують їм життя. Це тривожна ознака занепаду родинних цінностей.', NULL, TRUE, '2025-05-19 8:20:55'),
(13, 'Гіперопіка і розпещеність', 'Суспільство породжує дітей, які вважають усе належним і не готові до самопожертви чи вдячності.', NULL, TRUE, '2025-05-19 8:20:55'),
(14, 'Соціальна деградація молоді', 'Поведінка дітей — симптом глибших проблем: відсутності виховання, емоційної холодності або споживацького світогляду.', NULL, TRUE, '2025-05-19 8:20:55'),
(15, 'Моральна дегуманізація', 'Людина обурюється тим, що навіть героїчні вчинки не викликають належної реакції у сучасної молоді.', NULL, TRUE, '2025-05-19 8:20:55'),
(16, 'Недовіра до міжнародної допомоги', 'Автор сумнівається у щирості зовнішньої підтримки України — натякає, що вона відбувається заради грошей або вигоди.', NULL, TRUE, '2025-05-19 8:20:55'),
(17, 'Цинізм і скепсис у сприйнятті війни', 'Людина критикує публічні кампанії підтримки, вважаючи їх порожніми, лицемірними або мотивованими фінансовими причинами.', NULL, TRUE, '2025-05-19 8:20:55'),
(18, 'Розчарування у національному дискурсі', 'Пост відображає втому та зневіру у пафосних меседжах, які не підкріплені справжньою дією.', NULL, TRUE, '2025-05-19 8:20:55'),
(19, 'Критика патріотизму "на продаж"', 'Звучить гнів на тих, хто «грає» на патріотичних мотивах, щоб здобути популярність, репутацію або дохід.', NULL, TRUE, '2025-05-19 8:20:55'),
(20, 'Дефіцит моральних авторитетів', 'Людина потребує прикладів щирої, безкорисної доброти. Вона бачить в Анджеліні символ справжньої гуманності, що натякає на загальну відсутність таких фігур у нашій реальності.', NULL, TRUE, '2025-05-19 8:20:55'),
(21, 'Потреба в добрих новинах', 'Пост на тлі багатьох негативних — це крик душі про потребу в позитиві, у прикладах світла серед темряви.', NULL, TRUE, '2025-05-19 8:20:55'),
(22, 'Соціальна втома від негативу', 'Людина намагається триматися за позитив, аби врівноважити інформаційний простір, що насичений гнівом і критикою.', NULL, TRUE, '2025-05-19 8:20:55'),
(23, 'Порушення прав людини', 'Безпідставне затримання людини з ментальними розладами — це серйозне порушення базових прав.', NULL, TRUE, '2025-05-19 8:20:55'),
(24, 'Беззахисність вразливих груп', 'Психічно хворі, люди з інвалідністю не мають належного захисту від свавілля — їх легко зробити жертвою системи.', NULL, TRUE, '2025-05-19 8:20:55'),
(25, 'Інституційне беззаконня', 'Влада або силові структури можуть діяти без жодних правових підстав, що свідчить про деградацію державних механізмів.', NULL, TRUE, '2025-05-19 8:20:55'),
(26, 'Зневага до родин постраждалих', 'Те, що навіть матері не повідомляють місце перебування сина, показує глибоку моральну кризу системи.', NULL, TRUE, '2025-05-19 8:20:55'),
(27, 'Соціальна несправедливість у мобілізації', 'Автор висловлює обурення тим, що багатші та впливові люди уникають фронту, тоді як бідні несуть основний тягар.', NULL, TRUE, '2025-05-19 8:20:55'),
(28, 'Корупція в армійській системі', 'Існує припущення про систематичні зловживання під час призову — де одні можуть “відмазатись”, а інші ні.', NULL, TRUE, '2025-05-19 8:20:55'),
(29, 'Злість на тих, хто уникає відповідальності', 'Пост емоційний, бо він адресований “тим, хто ховає родичів” і водночас продовжує експлуатувати країну.', NULL, TRUE, '2025-05-19 8:20:55'),
(30, 'Проблема моральної нерівності', 'Люди обурені тим, що патріотизм розподілено нерівномірно — одні борються, інші заробляють.', NULL, TRUE, '2025-05-19 8:20:55'),
(31, 'Недовіра до міжнародних союзників', 'Людина піддає сумніву дії США, які водночас підтримують Україну, але, як вважає автор, своїми рішеннями посилюють ворогів.', NULL, TRUE, '2025-05-19 8:20:55'),
(32, 'Проблема глобального впливу конфліктів', 'Зв’язок між рішеннями США і смертями українців — це приклад як міжнародні політики мають локальні наслідки.', NULL, TRUE, '2025-05-19 8:20:55'),
(33, 'Безсила злість на політичні процеси', 'Відчуття, що звичайні люди не можуть вплинути на великі міжнародні рішення, які для них мають смертельні наслідки.', NULL, TRUE, '2025-05-19 8:20:55'),
(34, 'Некомпетентність експертів в медіа', 'Людина розчарована якістю думок, які подаються як фахові, хоча насправді не мають змісту.', NULL, TRUE, '2025-05-19 8:20:55'),
(35, 'Знецінення правової професії', 'Недолугі коментарі “експертів” псують репутацію всіх юристів, в тому числі добросовісних.', NULL, TRUE, '2025-05-19 8:20:55'),
(36, 'Зниження якості публічного дискурсу', 'Комунікаційний простір засмічено непрофесійними висловлюваннями, що деморалізує аудиторію.', NULL, TRUE, '2025-05-19 8:20:55'),
(37, 'Фрустрація через неефективне правосуддя', 'Автор посту вважає, що за красивими словами не стоїть жодних реальних рішень або дій.', NULL, TRUE, '2025-05-19 8:20:55'),
(38, 'Нерівність у застосуванні законів', 'Автор ставить під сумнів, чи правила однакові для всіх, чи лише для звичайних громадян — це вказує на недовіру до справедливості державної політики.', NULL, TRUE, '2025-05-19 8:20:55'),
(39, 'Соціальне розшарування', 'Існує проблема відчутного розділення між «мажорами» (заможними) та «роботягами» (простими людьми), які зазнають більше тиску з боку системи.', NULL, TRUE, '2025-05-19 8:20:55'),
(40, 'Бюрократична вибірковість', 'Люди відчувають, що державні служби обирають, кого контролювати, а кого — ні, створюючи відчуття дискримінації.', NULL, TRUE, '2025-05-19 8:20:55'),
(41, 'Культура споживання низькопробного контенту', 'Людина обурена тим, що глядачі підтримують продукт, який вона вважає безглуздим або принизливим — проблема погіршення смаків у суспільстві.', NULL, TRUE, '2025-05-19 8:20:55'),
(42, 'Відсутність критичного мислення у публіки', 'Автор шокований тим, що люди не усвідомлюють або не хочуть усвідомлювати низьку якість того, що споживають.', NULL, TRUE, '2025-05-19 8:20:55'),
(43, 'Масове схвалення поверхневого гумору', 'Це — симптом глибшої втоми чи розчарування: коли навіть інтелігентні люди перестають шукати щось вартісне й піддаються «сміховій масовці».', NULL, TRUE, '2025-05-19 8:20:55'),
(44, 'Відсутність культури поводження з відходами', 'Діти не мають розуміння, що смітити — погано. Це означає провал у вихованні та суспільній свідомості.', NULL, TRUE, '2025-05-19 8:20:55'),
(45, 'Безвідповідальність молодого покоління', 'Навіть базові норми поводження в публічному просторі порушуються — і це проблема, яка формує майбутнє суспільство.', NULL, TRUE, '2025-05-19 8:20:55'),
(46, 'Брак контролю з боку дорослих', 'Якщо діти так поводяться регулярно — отже, дорослі (батьки, школа, суспільство) не дають належного прикладу чи не встановлюють меж.', NULL, TRUE, '2025-05-19 8:20:55'),
(47, 'Проблеми міської чистоти', 'Сміття на вулицях формує неприємне та антисанітарне середовище — що погіршує життя всіх мешканців.', NULL, TRUE, '2025-05-19 8:20:55'),
(48, 'Побутова безпорадність у зоні війни', 'Людина говорить з іронією, але реальність така, що держава не забезпечує навіть найнеобхіднішого.', NULL, TRUE, '2025-05-19 8:20:55'),
(49, 'Побутові труднощі через обмежене електропостачання', 'Людина живе в умовах тотального дефіциту базових ресурсів (світло), але пристосувалась — що свідчить про втому і зневіру.', NULL, TRUE, '2025-05-19 8:20:55'),
(50, 'Конфлікт між “тими, хто лишився” і “тими, хто виїхав”', 'Автор демонструє роздратування на тих, хто скаржиться з-за кордону, не розуміючи реального стану в Україні.', NULL, TRUE, '2025-05-19 8:20:55'),
(51, 'Цинізм як форма захисту', 'Публікація має пасивно-агресивний тон — ознака того, що люди в стані виживання відгороджуються іронією.', NULL, TRUE, '2025-05-19 8:20:55'),
(52, 'Емоційна втома від скарг і жалісливості', 'Навіть звичайні пости у Facebook починають дратувати, коли в …вітла і тепла — це ознака глибокої психологічної перенапруги.', NULL, TRUE, '2025-05-19 8:20:55'),
(53, 'Проблема безпритульних тварин', 'Автор висловлює стурбованість щодо великої кількості безпритульних тварин у своєму місті.', NULL, TRUE, '2025-06-06 16:52:26'),
(54, 'Недостатність державної підтримки', 'Пост може відображати недостатність державних програм щодо стерилізації, притулків та адопції тварин.', NULL, TRUE, '2025-06-06 16:52:26'),
(55, 'Бездомність', 'Люди втратили свої будинки і не мають куди йти.', NULL, TRUE, '2025-06-06 17:20:37'),
(56, 'Брак допомоги постраждалим', 'Автор відчуває потребу допомогти, але, можливо, не знає, як це зробити.', NULL, TRUE, '2025-06-06 17:20:37'),
(57, 'Соціальна несправедливість', 'Автор відчуває неправду, що постраждалі залишаються без допомоги.', NULL, TRUE, '2025-06-06 17:20:37'),
(58, 'Економічні труднощі', 'Автор виражає стурбованість щодо стану малого бізнесу, можливо, через економічну кризу або недостатній державний підтримки.', NULL, TRUE, '2025-06-06 17:21:25'),
(59, 'Проблема стану доріг', 'Автор висловлює незадоволення станом доріг і шукає способи покращення ситуації.', NULL, TRUE, '2025-06-06 18:47:35'),
(60, 'Недостатність громадського фінансування', 'Пост може вказувати на недостатність державного фінансування для ремонту доріг.', NULL, TRUE, '2025-06-06 18:47:35'),
(61, 'Активізм', 'Автор хоче активно залучитися в розв''язання проблеми, шукаючи проекти для підтримки.', NULL, TRUE, '2025-06-06 18:47:35'),
(62, 'Недостатній контроль за безпекою собак у громадських місцях', 'Відсутність обов’язкового використання намордників для собак у громадських місцях створює ризики для безпеки людей, особливо дітей та людей із фобіями або алергіями. Це свідчить про недосконалість системи регулювання та контролю за поведінкою тварин, а також недостатню відповідальність власників. Така ситуація може призводити до нещасних випадків, травм та психологічних травм у постраждалих, що негативно впливає на рівень довіри у суспільстві та створює напружену атмосферу у громадських просторах.', NULL, TRUE, '2025-06-13 18:22:07'),
(63, 'Проблема безпритульних тварин', 'В місті спостерігається велика кількість безпритульних тварин, що створює небезпечні та нездорові умови для мешканців, сприяє поширенню хвороб і негативно впливає на естетичний вигляд населеного пункту. Відсутність системної роботи з контролю популяції тварин, недостатня кількість притулків і заходів з їхнього утримання призводить до зростання цієї проблеми, що викликає емоційний дискомфорт у громадян і знижує рівень безпеки в місті.', NULL, TRUE, '2025-06-30 23:30:50'),
(64, 'Моральна та психологічна травма населення', 'Масові вбивства, руйнування та насильство, що відбуваються під час війни, спричиняють глибоку психологічну травму у громадян, особливо у тих, хто втратив близьких, дім або відчуває безсилля. Відсутність адекватної психологічної підтримки та інформаційної роботи посилює почуття безнадії, страху і гнів, що може призвести до тривалих психологічних розладів і соціальної дезінтеграції. Також це сприяє поширенню дезінформації та емоційної маніпуляції, що ускладнює формування об’єднаної громадської позиції та спротиву.', NULL, TRUE, '2025-07-09 14:58:08'),
(65, 'Недостатня міжнародна реакція та підтримка', 'Світова спільнота демонструє недостатню активність у реагуванні на масштабні злочини та руйнування, що відбуваються в Україні. Це породжує відчуття байдужості, безкарності та знецінення людських життів, що підсилює відчуття безсилля у українців. Відсутність ефективних санкцій, дипломатичних зусиль і гуманітарної допомоги сприяє тому, що агресія продовжується, а людські трагедії залишаються без належної уваги та підтримки.', NULL, TRUE, '2025-07-09 14:58:08'),
(66, 'Відсутність єдності та активної громадянської позиції', 'Обурення та гнів, викликані війною та злочинами, не завжди перетворюються у системну громадянську активність або боротьбу за справедливість. Це може бути пов’язано з втомою, зневірою або відсутністю ефективних каналів для впливу. В результаті суспільство стає пасивним, що зменшує його здатність до опору та захисту своїх прав і інтересів. Відсутність об’єднаних дій і стратегічного плану у відповідь на агресію посилює відчуття безсилля і байдужості.', NULL, TRUE, '2025-07-09 14:58:09'),
(67, 'Відсутність етичних стандартів у медіа', 'Недотримання етичних норм у журналістиці, зокрема ігнорування важливості об’єктивності, приватності та відповідальності, сприяє формуванню токсичного медіа-простору. Це веде до зниження рівня довіри суспільства до ЗМІ, поширення маніпуляцій і дезінформації, а також шкодить репутації професії журналіста. Відсутність етичних правил і контролю створює ризики для громадського інформування та безпеки.', NULL, TRUE, '2025-07-09 15:01:56'),
(68, 'Маніпуляція інформацією та клікбейти', 'Використання сенсаційних заголовків і недостовірних або спотворених деталей у медіа сприяє поширенню дезінформації, зниженню довіри до ЗМІ та формуванню поверхневого сприйняття важливих тем. Це особливо небезпечно у контексті суспільних дискусій, де потрібна об’єктивність і глибина аналізу, а не емоційна провокація. Такі практики руйнують стандарти журналістики, сприяють формуванню негативного іміджу медіа та зменшують здатність громадян критично оцінювати інформацію, що особливо важливо у сучасних умовах інформаційної війни та боротьби за свідомість суспільства.', NULL, TRUE, '2025-07-09 15:21:12'),
(69, 'Маніпуляція інформацією та клікбейти', 'Використання сенсаційних заголовків і недостовірних або спотворених деталей для привернення уваги читачів призводить до зниження довіри до медіа, поширення дезінформації та формування поверхневого сприйняття важливих тем. Це руйнує етичні стандарти журналістики, підриває критичне мислення аудиторії і сприяє формуванню ілюзорних уявлень про реальні події, що особливо небезпечно у сучасних умовах інформаційної війни та суспільної поляризації.', NULL, TRUE, '2025-07-09 15:23:57'),
(70, 'Недобросовісне висвітлення важливих тем', 'Зневажливе або поверхневе висвітлення важливих суспільних питань, зокрема ігнорування ключових аспектів або додавання сенсаційних деталей без підстав, сприяє формуванню ілюзорних уявлень у громадськості. Це знижує рівень інформованості, підсилює політичну та соціальну поляризацію, а також руйнує довіру до ЗМІ як до джерела об’єктивної інформації. В результаті суспільство втрачає здатність до критичного аналізу і прийняття зважених рішень, що посилює соціальні конфлікти та дезінформацію.', NULL, TRUE, '2025-07-09 15:23:57'),
(71, 'Маніпуляція інформацією та клікбейти', 'Використання сенсаційних заголовків і недостовірних або спотворених деталей для привернення уваги читачів призводить до зниження довіри до медіа, поширення дезінформації та формування поверхневого сприйняття важливих тем. Це руйнує етичні стандарти журналістики, підриває критичне мислення аудиторії і сприяє формуванню споживачів інформації, які не здатні відрізняти правду від маніпуляції. Така практика шкодить суспільству, особливо у контексті важливих соціальних і політичних питань, що вимагають об’єктивного висвітлення.', NULL, TRUE, '2025-07-09 15:27:57'),
(72, 'Моральна та психологічна травма населення', 'Масові вбивства, руйнування та жорстокі злочини, що відбуваються під час війни, спричиняють глибоку психологічну травму у громадян, особливо у тих, хто втратив близьких, дім або відчуває безсилля. Це породжує почуття безнадійності, страху та гнів, що ускладнює процес відновлення та сприяє поширенню психологічних розладів, таких як посттравматичний стресовий синдром. Відсутність системної психологічної підтримки та інформаційної роботи посилює цю кризу, поглиблюючи розкол у суспільстві та знижуючи його стійкість до викликів війни.', NULL, TRUE, '2025-07-09 15:28:56'),
(73, 'Недостатня міжнародна реакція та підтримка', 'Світова спільнота демонструє недостатню активність у реагуванні на агресію та злочини, скоєні російськими військами, що викликає відчуття безкарності та знецінення людських життів. Це сприяє поширенню відчуття, що міжнародні інституції та лідери не здатні захистити мирне населення або вплинути на ситуацію. Така пасивність підсилює відчуття беззахисності у українців і зменшує мотивацію до боротьби за свою незалежність і безпеку, а також знижує довіру до глобальної системи безпеки.', NULL, TRUE, '2025-07-09 15:28:56'),
(74, 'Інформаційна війна та дезінформація', 'Поширення неправдивої або односторонньої інформації, а також ідеологічна пропаганда, сприяють формуванню негативного образу України та її захисників у світовій громадській думці. Це ускладнює міжнародну підтримку, створює ілюзію байдужості або навіть симпатій до агресора, посилює розкол у суспільстві та зменшує здатність громадян критично оцінювати інформацію. Внаслідок цього зростає рівень недовіри до ЗМІ, посилюється політична поляризація і знижується мобілізація суспільства у боротьбі за свободу та незалежність.', NULL, TRUE, '2025-07-09 15:28:56'),
(75, 'Відсутність єдності та активної громадянської позиції', 'Обурення та гнів, викликані війною, не завжди перетворюються у конструктивні дії або активну громадянську позицію. Це може сприяти апатії, розчаруванню та розколам у суспільстві, що зменшує здатність країни до опору та відновлення. Відсутність системної роботи з формування патріотичних цінностей, громадської відповідальності та солідарності призводить до ослаблення внутрішнього фронту, що є критичним у часи війни.', NULL, TRUE, '2025-07-09 15:28:56'),
(76, 'Проблема доброти і емпатії', 'Автор показує стурбованість до безпритульних тварин, що свідчить про бажання висловити доброту та емпатію до цих істот, відображаючи ширше соціальне питання про відповідальність суспільства за безпритульних.', NULL, FALSE, CURRENT_TIMESTAMP),
(77, 'Соціальна ізоляція тварин', 'Заклик про допомогу безпритульним тваринам може свідчити про те, що автор усвідомлює соціальну ізоляцію тварин, що не мають дому, та їх вразливість, що відображає відчуття несправедливості в суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(78, 'Внутрішня тривога через соціальні проблеми', 'Тема безпритульних тварин може відображати внутрішню тривогу автора щодо загального стану суспільства, де емоційний стан і життя тварин стають відображенням людських проблем.', NULL, FALSE, CURRENT_TIMESTAMP),
(79, 'Тема соціальної відповідальності', 'Автор загострює увагу на проблемі безпритульних тварин, що може свідчити про його чутливість до соціальних проблем і бажання впливати на суспільство.', NULL, FALSE, CURRENT_TIMESTAMP),
(80, 'Емпатія та гуманність', 'Запит на допомогу безпритульним тваринам може вказувати на глибоке почуття емпатії автора та бажання захищати тих, хто не може захистити себе.', NULL, FALSE, CURRENT_TIMESTAMP),
(81, 'Відсутність ресурсів', 'Можливо, автор відчуває безсилля або брак ресурсів для реальної допомоги, що може свідчити про загальну кризу підтримки у суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(82, 'Гуманність і співчуття', 'Автор турбується про безпритульних тварин, що вказує на його чутливість до соціальних проблем і прагнення допомогти тим, хто не може захистити себе.', NULL, FALSE, CURRENT_TIMESTAMP),
(83, 'Соціальна відповідальність', 'Запитання "як допомогти" вказує на бажання автора знайти способи вплинути на позитивні зміни у суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(84, 'Критичне ставлення до системи', 'Проблема безпритульних тварин може відображати незадоволеність автора соціальними структурами, які не забезпечують належний догляд за ними.', NULL, FALSE, CURRENT_TIMESTAMP),
(85, 'Гуманність і співчуття', 'Автор турбується про безпритульних тварин, що вказує на його чутливість до соціальних проблем і прагнення допомогти тим, хто не може захистити себе.', NULL, FALSE, CURRENT_TIMESTAMP),
(86, 'Соціальна відповідальність', 'Запитання "як допомогти" вказує на бажання автора знайти способи вплинути на позитивні зміни у суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(87, 'Критичне ставлення до системи', 'Проблема безпритульних тварин може відображати незадоволеність автора соціальними структурами, які не забезпечують належний догляд за ними.', NULL, FALSE, CURRENT_TIMESTAMP),
(88, 'Соціальна відповідальність', 'Автор, ставлячи питання про допомогу безпритульним тваринам, вказує на низький рівень соціальної відповідальності суспільства. Це свідчить про потребу змін у свідомості людей щодо ставлення до тварин і їхніх прав.', NULL, FALSE, CURRENT_TIMESTAMP),
(89, 'Емпатія і чутливість', 'Звернення до проблеми безпритульних тварин свідчить про високий рівень емпатії автора. Це може вказувати на те, що він або вона переживає труднощі у сприйнятті страждань інших і прагне позитивних змін.', NULL, FALSE, CURRENT_TIMESTAMP),
(90, 'Відчуття безвиході', 'Питання ''як допомогти'' може вказувати на відчуття безвиході у вирішенні цієї проблеми. Автор може відчувати фрустрацію через нерозуміння або байдужість з боку інших людей, що призводить до відчуття самотності у боротьбі з цією соціальною проблемою.', NULL, FALSE, CURRENT_TIMESTAMP),
(91, 'Проблема безпритульних тварин', 'В повідомленні акцентується на потребі допомоги безпритульним тваринам, що свідчить про соціальну проблему насильства чи байдужості до тварин, а також недостатнє регулювання у сфері відповідального поводження із тваринами.', NULL, FALSE, CURRENT_TIMESTAMP),
(92, 'Суспільна відповідальність', 'Автор піднімає питання про те, як допомогти, що може свідчити про усвідомлення своєї ролі в суспільстві та потребу активізуватися для покращення ситуації. Це може вказувати на брак активності з боку громади та суспільства загалом.', NULL, FALSE, CURRENT_TIMESTAMP),
(93, 'Емоційний стан', 'Тема безпритульних тварин може бути емоційно навантаженою. Автор може відчувати тривогу або співчуття до страждання тварин, що відображає більшу проблему ставлення до тих, хто зазвичай не може за себе постояти.', NULL, FALSE, CURRENT_TIMESTAMP),
(94, 'Безпритульні тварини', 'Автор висловлює турботу про безпритульних тварин, що свідчить про глибоке співчуття до тих, хто опинився у складних умовах. Це може вказувати на соціальну відповідальність і бажання змінити ситуацію в суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(95, 'Відчуття безсилля', 'Запитання ''як допомогти'' може свідчити про відчуття безсилля або невпевненості в можливостях змінити ситуацію. Це вказує на те, що автор шукає рішення, але може відчувати, що його зусилля обмежені.', NULL, FALSE, CURRENT_TIMESTAMP),
(96, 'Проблема байдужості суспільства', 'Проблема безпритульних тварин часто є наслідком байдужості суспільства до тваринного світу. Автор може підкреслювати цю соціальну проблему, вказуючи на необхідність більшої свідомості та уваги до тварин.', NULL, FALSE, CURRENT_TIMESTAMP),
(97, 'Соціальна справедливість', 'Автор порушує тему допомоги безпритульним тваринам, що може свідчити про чутливість до соціальної нерівності та несправедливості в суспільстві. Це вказує на бажання змінити ситуацію та боротися за права тварин.', NULL, FALSE, CURRENT_TIMESTAMP),
(98, 'Емпатія та турбота', 'Висловлення concern щодо безпритульних тварин говорить про емпатію та бажання піклуватися про тих, хто не може за себе постояти, що може вказувати на психологічну потребу допомагати іншим.', NULL, FALSE, CURRENT_TIMESTAMP),
(99, 'Відчуження від суспільства', 'Тематика безпритульних тварин може також відображати почуття відчуження, оскільки така ситуація може бути символом більш глибоких соціальних проблем у суспільстві, включаючи ігнорування потреб страждаючих.', NULL, FALSE, CURRENT_TIMESTAMP),
(100, 'Соціальна відповідальність', 'Проблема, що стосується порушення обов''язків суспільства перед тваринами. Автор, можливо, відчуває занепокоєння через байдужість до безпритульних тварин і прагне привернути увагу до необхідності допомоги.', NULL, FALSE, CURRENT_TIMESTAMP),
(101, 'Емпатія', 'Відчуття співчуття до страждань безпритульних тварин може свідчити про глибоке співчуття автора. Це також може вказувати на внутрішнє бажання впливати на життя інших істот.', NULL, FALSE, CURRENT_TIMESTAMP),
(102, 'Соціальна ізоляція', 'Автор може відчувати ізоляцію в своєму бажанні допомагати, якщо оточуючі не розділяють його погляди чи активності. Це може спричиняти відчуття самотності в боротьбі за права безпритульних тварин.', NULL, FALSE, CURRENT_TIMESTAMP),
(103, 'Соціальна турбота', 'Автор переймається долею безпритульних тварин, що свідчить про чутливість до соціальних проблем та бажання допомогти. Це може вказувати на глибоку стурбованість про добробут тварин та їхнє місце у суспільстві.', NULL, FALSE, CURRENT_TIMESTAMP),
(104, 'Емпатія', 'Автор виявляє емпатію до безпритульних тварин, що може свідчити про їхній внутрішній порив допомогти, а також може натякати на власні емоційні переживання та бажання навести порядок у житті, що відображає гуманістичний підхід.', NULL, FALSE, CURRENT_TIMESTAMP),
(105, 'Відчуття безсилля', 'Заклик допомогти безпритульним тваринам може також відображати певне відчуття безсилля автора перед масовими соціальними проблемами, такими як безпритульність тварин, і бажання знайти спосіб внести зміни в цю ситуацію.', NULL, FALSE, CURRENT_TIMESTAMP)
INSERT INTO public.solutions (solution_id, name, context, content, created_at) OVERRIDING SYSTEM VALUE VALUES
(1, 'Нульова толерантність до воєнних злочинців', 'Організація тематичних лекцій і дискусій про злочини проти мирного населення, документування свідчень та підтримка міжнародних трибуналів для забезпечення правди, відповідальності та справедливості.', NULL, '2025-05-19 9:32:24'),
(2, 'Меморіалізація жертв війни', 'Проведення виставок фотосвідчень і зустрічей із родинами загиблих, а також створення онлайн-архіву історій потерпілих для вшанування їхньої пам’яті.', NULL, '2025-05-19 9:32:24'),
(3, 'Інформаційні кампанії проти апатії', 'Запуск інтерактивних платформ із реальними свідченнями та закликами до дії, а також проведення вебінарів із залученням експертів для підвищення обізнаності й мотивації громадськості.', NULL, '2025-05-19 9:32:24'),
(4, 'Етичні стандарти для ЗМІ', 'Проведення тренінгів для журналістів, розробка кодексів професійної етики та публічний аудит заголовків із метою зміцнення достовірності й відповідальності медіа.', NULL, '2025-05-19 9:32:24'),
(5, 'Центр перевірки фактів та медіаосвіти', 'Співпраця з незалежними організаціями для глибокого аналізу медіаматеріалів та розробки практичних гідів із фактчекінгу й медіаграмотності.', NULL, '2025-05-19 9:32:24'),
(6, 'Політика захисту приватного життя', 'Впровадження принципів конфіденційності та згоди під час збору особистих даних, а також аудит дотримання прав респондентів під час інтерв’ю.', NULL, '2025-05-19 9:32:24'),
(7, 'Курси медіаграмотності для аудиторії', 'Організація воркшопів і онлайн-курсів із критичного аналізу медіаконтенту для навчання вмінню «читати між рядків» та перевіряти факти.', NULL, '2025-05-19 9:32:24'),
(8, 'Тренінги з емпатичної педагогіки', 'Розробка навчальних модулів для вчителів із техніками активного слухання й кризового реагування для формування емпатії та психологічної підтримки.', NULL, '2025-05-19 9:32:24'),
(9, 'Програми морального виховання в школах', 'Інтеграція уроків із обговоренням етичних дилем та рольовими іграми для виховання цінностей, відповідального ставлення та соціалізації учнів.', NULL, '2025-05-19 9:32:24'),
(10, 'Арт- і ігрова терапія для дітей', 'Регулярні творчі майстер-класи з арт- і ігровою терапією, спрямовані на відновлення та згуртування дітей, які пережили воєнну травму.', NULL, '2025-05-19 9:32:24'),
(11, 'Адвокація освітніх реформ', 'Проведення пілотних проєктів із оновлення шкільних програм та відкриті дискусії з батьками й педагогами для просування освітніх реформ.', NULL, '2025-05-19 9:32:24'),
(12, 'Сімейні зустрічі та тренінги', 'Фасилітовані зустрічі для батьків і дітей з метою відновлення довіри, взаємоповаги та взаєморозуміння в родинах.', NULL, '2025-05-19 9:32:24'),
(13, 'Курси самостійності для молоді', 'Тренінги з побутових навичок та програми наставництва для підлітків, спрямовані на розвиток відповідальності та самостійності через волонтерські ініціативи.', NULL, '2025-05-19 9:32:24'),
(14, 'Молодіжні центри з наставництвом', 'Створення молодіжних хабів із менторськими програмами та профорієнтаційними проєктами для розвитку навичок і підтримки молоді.', NULL, '2025-05-19 9:32:24'),
(15, 'Ініціативи героїзації захисників', 'Організація зустрічей з ветеранами та створення мультимедійних нарисів про їхній шлях із метою вшанування захисників і мотивації суспільства.', NULL, '2025-05-19 9:32:24'),
(16, 'Прозорість міжнародної допомоги', 'Публікація щомісячних онлайн-звітів із детальним переліком отриманих і витрачених коштів для забезпечення прозорості та довіри до міжнародної допомоги.', NULL, '2025-05-19 9:32:24'),
(17, 'Мотиваційні історії про виживання', 'Проведення серії офлайн-зустрічей, де свідки обстрілів діляться історіями виживання для натхнення та зміцнення стійкості громади.', NULL, '2025-05-19 9:32:24'),
(18, 'Громадські форуми для діалогу', 'Регулярні відкриті форуми з лідерами думок і представниками влади для обговорення актуальних питань, залучення громадськості та сприяння впливу.', NULL, '2025-05-19 9:32:24'),
(19, 'Маркування етичних патріотичних проєктів', 'Розробка та впровадження знака якості для неприбуткових проєктів, які відповідають стандартам чесності, прозорості та відсутності комерційного інтересу.', NULL, '2025-05-19 9:32:24'),
(20, 'Пошук та промоція моральних авторитетів', 'Кампанії з висвітлення прикладів добровольців без медійних амбіцій із метою популяризації моральних авторитетів і лідерства.', NULL, '2025-05-19 9:32:24'),
(21, 'Огляд позитивних новин', 'Щотижневий електронний бюлетень із добрими та надихаючими новинами для балансу інформаційного простору та психологічної підтримки.', NULL, '2025-05-19 9:32:24'),
(22, 'Ресурс із практиками проти вигорання', 'Створення онлайн-платформи з релакс-відео та рекомендаціями психологів щодо практик mindfulness і самодопомоги для запобігання вигоранню.', NULL, '2025-05-19 9:32:24'),
(23, 'Юридичні клініки з прав людини', 'Надання безкоштовних консультацій і супроводу стратегічних позовів із захисту прав людини до міжнародних інстанцій через юридичні клініки.', NULL, '2025-05-19 9:32:24'),
(24, 'Мобільні соціальні працівники для вразливих', 'Формування мобільних бригад соціальних працівників для регулярних виїздів до маломобільних та вразливих груп із ментальнокризовою підтримкою.', NULL, '2025-05-19 9:32:24'),
(25, 'Моніторинг правопорушень владою', 'Запуск незалежної онлайн-платформи для спостереження за діями влади та публікації звітів про зловживання з метою збільшення тиску та прозорості.', NULL, '2025-05-19 9:32:24'),
(26, 'Сімейна підтримка родин потерпілих', 'Організація регулярних груп взаємодопомоги та надання соціальної, психологічної та фінансової підтримки родинам потерпілих.', NULL, '2025-05-19 9:32:24'),
(27, 'Забезпечення рівних умов мобілізації', 'Кампанії за уніфіковані правила мобілізації та незалежний нагляд за викликом до війська для забезпечення законності та рівності.', NULL, '2025-05-19 9:32:24'),
(28, 'Платформа анонімного повідомлення про корупцію', 'Створення анонімного порталу для повідомлень про корупцію в армії з проведенням аудиту та розслідувань кожного випадку.', NULL, '2025-05-19 9:32:24'),
(29, 'Кампанії проти ухиляння від служби', 'Реалізація медіапроєктів та публікація публічних кейсів про наслідки ухиляння від служби для формування соціального тиску та відповідальності.', NULL, '2025-05-19 9:32:24'),
(30, 'Програми наставництва для небайдужих', 'Надання грантів і стажувань для активістів із регіонів у рамках програм наставництва для розвитку навичок та рівних можливостей.', NULL, '2025-05-19 9:32:24'),
(31, 'Панелі прозорості для міжнародних партнерів', 'Проведення публічних брифінгів і сесій питань і відповідей з дипломатами та аналітиками для демонстрації результатів і планів міжнародної співпраці.', NULL, '2025-05-19 9:32:24'),
(32, 'Аналітичні брифінги про глобальні наслідки', 'Підготовка аналітичних звітів та інфографіки про вплив політичних рішень на місцеві громади з наступними дискусійними клубами.', NULL, '2025-05-19 9:32:24'),
(33, 'Проєкти громадянської участі', 'Тренінги з організації місцевих кампаній та спостереження за виборами для залучення громадян до активної громадянської позиції.', NULL, '2025-05-19 9:32:24'),
(34, 'Журналістська школа етики', 'Курси з етики та професійних стандартів для медіаекспертів та журналістів у рамках спеціалізованої школи.', NULL, '2025-05-19 9:32:24'),
(35, 'Ініціативи безоплатної юридичної допомоги', 'Програми для молодих юристів із надання безоплатної юридичної допомоги та ефективного захисту громадян через pro bono ініціативи.', NULL, '2025-05-19 9:32:24'),
(36, 'Дебатні клуби та модерація дискусій', 'Створення дебатних клубів у вишах та громадських центрах із модерацією дискусій для розвитку аргументації, толерантності та конструктивного діалогу.', NULL, '2025-05-19 9:32:24'),
(37, 'Стратегічні судові позови проти порушень', 'Підтримка стратегічних судових позовів проти порушень прав із метою формування прецедентів та сприяння судовій реформі.', NULL, '2025-05-19 9:32:24'),
(38, 'Програми юридичної допомоги для вразливих', 'Відкриття виїзних юридичних пунктів у малих містечках і селах для надання консультацій та захисту вразливих груп.', NULL, '2025-05-19 9:32:24'),
(39, 'Ініціативи зі зміцнення громади', 'Організація заходів, що об’єднують різні соціальні групи за спільними інтересами для зміцнення єдності громади.', NULL, '2025-05-19 9:32:24'),
(40, 'Платформи цифрового врядування для звітності', 'Розробка інтерактивних e-government сервісів з відкритими API та зворотним зв’язком для моніторингу роботи державних служб.', NULL, '2025-05-19 9:32:24'),
(41, 'Арт-фестивалі високоякісного змісту', 'Проведення арт-фестивалів і кінопоказів з високоякісним контентом для просвіти та культурного збагачення аудиторії.', NULL, '2025-05-19 9:32:24'),
(42, 'Тренінги з критичного мислення', 'Інтерактивні воркшопи з критичного мислення в школах і університетах для вдосконалення аналітичних здібностей і вмінь фактчекінгу.', NULL, '2025-05-19 9:32:24'),
(43, 'Вечори стендапу про соціальні теми', 'Серія вечорів стендапу з соціальною сатирою, яка поєднує гумор і важливі меседжі для широкої аудиторії.', NULL, '2025-05-19 9:32:24'),
(44, 'Еко-освітні програми в школах', 'Впровадження екоуроків із сортування та повторного використання разом із практичними акціями з прибирання довкола шкіл.', NULL, '2025-05-19 9:32:24'),
(45, 'Програми розвитку молодіжного лідерства', 'Інтенсивні курси лідерства для старшокласників із фокусом на проактивності, відповідальності та навичках управління проєктами.', NULL, '2025-05-19 9:32:24'),
(46, 'Майстер-класи для батьків та шкільні ради', 'Проведення воркшопів для батьків і створення шкільних рад для зміцнення співпраці, встановлення кордонів та впливу на дисципліну.', NULL, '2025-05-19 9:32:24'),
(47, 'Дні прибирання громади', 'Регулярні суботники з інструментами та матеріалами для прибирання громадських просторів, спрямовані на екологічну свідомість і волонтерство.', NULL, '2025-05-19 9:32:24'),
(48, 'Мобільні центри побутової підтримки', 'Створення мобільних хабів із побутовою підтримкою: видача інструментів, генераторів і консультації з життєвих навичок на колесах.', NULL, '2025-05-19 9:32:24'),
(49, 'Роздача сонячних зарядних пристроїв', 'Організація доставки сонячних зарядних пристроїв дронами та їхнє обслуговування для забезпечення автономного живлення.', NULL, '2025-05-19 9:32:24'),
(50, 'Діалогові майданчики для діаспори', 'Запуск онлайн-форумів для діаспори й місцевих жителів з метою обміну досвідом, налагодження зв’язків та підтримки інтеграції.', NULL, '2025-05-19 9:32:24'),
(51, 'Групи взаємопідтримки проти цинізму', 'Регулярні зустрічі груп підтримки з психотерапевтом і ветеранами для подолання цинізму через емпатію та взаємодопомогу.', NULL, '2025-05-19 9:32:24'),
(52, 'Позитивні тематичні зустрічі', 'Проведення лінійки лекцій і майстер-класів із фокусом на відновленні ресурсів, де учасники обмінюються досвідом і надихають одне одного.', NULL, '2025-05-19 9:32:24'),
(53, 'Недостатній контроль за безпекою собак у громадських місцях', 'Запровадити обов’язкове використання намордників для собак у всіх громадських місцях, особливо там, де є скупчення людей. Встановити чіткі правила та штрафи для власників, які порушують ці норми. Провести інформаційні кампанії для підвищення обізнаності про відповідальність власників та важливість безпеки для всіх учасників громадського життя. Впровадити систему реєстрації та контролю за поведінкою тварин через муніципальні служби, а також створити пункти для навчання власників правильній поведінці з собаками та їхньому вихованню.', NULL, '2025-06-13 18:22:07')
